import type { Drill } from "./types";

// Lawyer / early drills, keyed by module slug — 25 per module.
// Pitched at a law-firm associate or junior in-house counsel: research memos to
// partners, client status emails, plain-language summaries of case law and
// contract terms, discovery updates, and flagging risks. Merged into course.ts.
export const LAWYER_EARLY_DRILLS: Record<string, Drill[]> = {
  "lead-with-the-point": [
    {"id":"lead-law-early-01","level":"early","profession":"lawyer","title":"The memo that buries the answer","scenario":"A partner asked you to research whether the client's non-compete is enforceable. Your draft memo walks through eight cases in chronological order before reaching the answer on page four: it is likely enforceable with one fix to the geographic scope. Partners read the first paragraph and skim the rest.","task":"Write a 2-3 sentence memo opening that states the answer first.","tips":["Sentence one is the conclusion: likely enforceable, with one fix.","The case walk-through is support — it comes after the answer.","Name the one action that changes the outcome."],"focus":["structure","clarity"],"placeholder":"The non-compete is likely enforceable if the geographic scope is narrowed —"},
    {"id":"lead-law-early-02","level":"early","profession":"lawyer","title":"The deposition reschedule email","scenario":"Opposing counsel just moved the key deposition from March 12 to March 26. The client's HR director, who is coordinating three witnesses' calendars, needs to know now. Your draft opens with two paragraphs about why opposing counsel requested the change.","task":"Write a 2-3 sentence email that leads with the new date and what the client must do.","tips":["First sentence: the deposition moved to March 26.","Second: what the HR director needs to re-book.","Why it moved is one clause, not two paragraphs."],"focus":["clarity","impact"],"placeholder":"The Chen deposition has moved to March 26 —"},
    {"id":"lead-law-early-03","level":"early","profession":"lawyer","title":"The scope question you keep postponing","scenario":"The assigning partner asked you to review the vendor agreements, but you're not sure whether that includes the three expired agreements still referenced in the data room. Guessing wrong costs a day either way. Your draft message explains the whole data-room layout before asking.","task":"Write a message that puts the yes/no question in the first sentence.","tips":["Lead with the question: include the expired agreements or not?","Give one sentence of context — enough to answer, no more.","A bounded question gets answered between meetings."],"focus":["clarity","concision"],"placeholder":"Quick scope check: should the vendor review include the three expired agreements?"},
    {"id":"lead-law-early-04","level":"early","profession":"lawyer","title":"The document that changes the case","scenario":"Reviewing the client's email production, you found a 2022 message where their sales lead promised the disputed discount in writing. This directly undercuts the client's position. Your draft to the partner recounts your review methodology before mentioning the email.","task":"Write a 2-3 sentence message that leads with the finding and its significance.","tips":["First sentence: what you found and why it matters.","Bates number and location are support, not the opening.","Flag significance plainly — the partner should feel the weight in line one."],"focus":["impact","structure"],"placeholder":"I found an email that directly undercuts our discount argument —"},
    {"id":"lead-law-early-05","level":"early","profession":"lawyer","title":"The motion result, eventually","scenario":"The court just granted the motion to dismiss two of the four claims against your client. You're drafting the email to the lead partner, and your opening recaps the briefing schedule and oral argument before stating the result.","task":"Write an email opening that states the result in sentence one.","tips":["Lead with the outcome: two of four claims dismissed.","Say which two immediately — that's the substance.","The procedural recap is a footnote, if anything."],"focus":["clarity","structure"],"placeholder":"The court dismissed the fraud and negligence claims —"},
    {"id":"lead-law-early-06","level":"early","profession":"lawyer","title":"The extension that needs a fast yes","scenario":"Opposing counsel offered a two-week extension on discovery responses, but only if you accept by tomorrow. You need the client contact's approval today. Your draft explains the discovery timeline history before making the ask.","task":"Write a 2-3 sentence email that leads with the ask and the deadline.","tips":["First sentence: I need your approval by tomorrow for a two-week extension.","State your recommendation — don't just relay the offer.","History goes below the ask or gets cut."],"focus":["clarity","impact"],"placeholder":"I need your OK by tomorrow morning: opposing counsel offered a two-week extension —"},
    {"id":"lead-law-early-07","level":"early","profession":"lawyer","title":"The 'when will the contract be ready' reply","scenario":"The client's operations manager emailed asking when the revised services agreement will be ready to sign. The honest answer is Thursday. Your draft opens by describing the three open issues you're still resolving with the other side.","task":"Write a reply that gives the date first, then the one caveat that matters.","tips":["Thursday is the answer to the question asked — lead with it.","One caveat, stated as a condition, not a story.","Don't make a client dig for a date."],"focus":["clarity","precision"],"placeholder":"Thursday, assuming the other side accepts our liability cap language."},
    {"id":"lead-law-early-08","level":"early","profession":"lawyer","title":"The two-deadline collision","scenario":"The Meridian brief and the Halvorsen due-diligence summary are both due Friday, and you can only finish one well. You need the partner to prioritize. Your draft describes each matter's background in detail before surfacing the conflict.","task":"Write a message that leads with the conflict and the decision you need.","tips":["First sentence: both are due Friday and I can finish one — which takes priority?","Give the partner a one-line cost of each choice.","Flagging early is the professional move; burying it is the risk."],"focus":["clarity","structure"],"placeholder":"Two Friday deadlines have collided and I need your call on priority —"},
    {"id":"lead-law-early-09","level":"early","profession":"lawyer","title":"The citation error you just caught","scenario":"You found an error in the brief filed yesterday: footnote 14 cites the wrong case reporter. It's fixable with an errata letter, but the partner needs to know now. Your instinct is to open with how the error happened.","task":"Write a 2-3 sentence message that leads with the error and the fix.","tips":["First line: what's wrong and that there is a standard fix.","Own it plainly — no excuse preamble.","The how-it-happened can wait until asked."],"focus":["clarity","impact"],"placeholder":"I caught a citation error in yesterday's filing — fixable with an errata letter."},
    {"id":"lead-law-early-10","level":"early","profession":"lawyer","title":"The settlement counteroffer relay","scenario":"Opposing counsel just countered at $340,000 — up from their last position of $250,000 and within the range the client authorized you to explore. Your draft email to the partner narrates the whole call before stating the number.","task":"Write an email that leads with the number and what it means.","tips":["The number is the news — sentence one.","Say immediately that it's inside the authorized range.","Call color comes after, briefly."],"focus":["structure","impact"],"placeholder":"They countered at $340,000 — inside the client's authorized range."},
    {"id":"lead-law-early-11","level":"early","profession":"lawyer","title":"The research pick, stated","scenario":"A senior associate asked whether to argue the contract claim under New York or Delaware law. Your research points clearly to New York. Your reply drafts three paragraphs of comparative analysis before committing to a recommendation.","task":"Rewrite so your recommendation comes first, with the two strongest reasons after.","tips":["State the pick in sentence one: New York.","Two reasons beat five — pick the strongest.","The full comparison can live in an attachment."],"focus":["structure","clarity"],"placeholder":"Argue it under New York law —"},
    {"id":"lead-law-early-12","level":"early","profession":"lawyer","title":"The document request to the paralegal","scenario":"You need the paralegal to pull all board minutes from 2021-2023 and the signed versions of the two stock purchase agreements by tomorrow at noon for a partner meeting. Your draft message opens with background on the matter she already knows.","task":"Write a message that leads with exactly what you need and by when.","tips":["First line: the deliverable and the deadline.","List the items so nothing needs a follow-up question.","Context only where it changes what she pulls."],"focus":["clarity","precision"]},
    {"id":"lead-law-early-13","level":"early","profession":"lawyer","title":"The pre-call one-liner","scenario":"The partner is dialing into a client call in five minutes and asks you to catch her up on the lease dispute by text. Everything she needs: the landlord's lawyer conceded the notice defect, so the client's termination likely stands.","task":"Write a 1-2 sentence text that leads with the takeaway she can use on the call.","tips":["One headline: they conceded the notice defect.","Then the consequence: our termination likely stands.","No throat-clearing — she's reading this while dialing."],"focus":["concision","impact"],"placeholder":"Landlord's counsel conceded the notice defect —"},
    {"id":"lead-law-early-14","level":"early","profession":"lawyer","title":"The budget overrun heads-up","scenario":"Document review is running heavier than scoped: the fee estimate assumed 20,000 documents and the collection came back at 55,000. The client contact needs to hear this from you before the invoice arrives. Your draft opens with a review-process explainer.","task":"Write a 2-3 sentence heads-up that leads with the number change and its fee impact.","tips":["Lead with the delta: 55,000 documents, not 20,000.","Translate it to fees in the same breath.","Offer the next step — options call, revised estimate."],"focus":["clarity","impact"],"placeholder":"Heads-up: the document collection came back at 55,000 documents, almost triple the estimate —"},
    {"id":"lead-law-early-15","level":"early","profession":"lawyer","title":"The follow-up that finally asks","scenario":"You asked the client's finance contact for the 2023 invoices eight days ago; discovery responses are due in two weeks and you can't draft without them. Your follow-up draft opens with apologies for bothering him again.","task":"Write a follow-up that leads with the ask and the real deadline behind it.","tips":["Name the documents and the date you need them by.","Explain the deadline in one clause — it's motivation, not backstory.","Cut the apology; a clear ask is not an imposition."],"focus":["clarity","impact"],"placeholder":"I still need the 2023 invoices by Friday —"},
    {"id":"lead-law-early-16","level":"early","profession":"lawyer","title":"The weekly matter email that meanders","scenario":"Your Friday status email to the partner covers the Ashford matter. The one thing that actually needs her attention: the client hasn't approved the settlement authority increase, and mediation is Tuesday. Your draft lists completed tasks first.","task":"Write the opening 1-2 sentences so the item needing action comes first.","tips":["Lead with the open decision, not the finished work.","Attach the deadline to it: mediation is Tuesday.","Completed tasks are the appendix of a status email."],"focus":["structure","clarity"]},
    {"id":"lead-law-early-17","level":"early","profession":"lawyer","title":"The 'can we say yes' relay","scenario":"The partner asked you one question in the hallway: can the client terminate the distributor agreement without cause? You've done the reading — yes, with 90 days' notice. Your drafted reply restates the question and describes the contract structure before answering.","task":"Write a reply that answers in the first five words, then adds the one condition.","tips":["'Yes, with 90 days' notice' is a complete first sentence.","The clause reference is support, not the lede.","Short answers to short questions build trust."],"focus":["concision","clarity"],"placeholder":"Yes — with 90 days' written notice under Section 11.2."},
    {"id":"lead-law-early-18","level":"early","profession":"lawyer","title":"The intake summary for the partner","scenario":"You did the intake call for a prospective employment matter. The headline: the termination happened 23 months ago, so the two-year filing deadline leaves only one month to act. Your draft summary starts with the client's full employment history.","task":"Write a 2-3 sentence summary that leads with the urgency.","tips":["The deadline is the point — one month to file.","History matters only as it affects the decision to take the case.","Make the required decision explicit: take it or decline fast."],"focus":["impact","structure"],"placeholder":"Time-sensitive intake: the filing deadline is in roughly one month."},
    {"id":"lead-law-early-19","level":"early","profession":"lawyer","title":"The redline cover email","scenario":"You're returning the redlined supply agreement to the client's procurement lead. Of your 14 changes, only two need his input: the payment terms and the termination trigger. Your draft walks through all 14 in order.","task":"Write a cover email that leads with the two decisions he owns.","tips":["First line: 14 changes, two need your call.","Name the two and what you recommend for each.","The other twelve get one summary sentence."],"focus":["structure","audience"],"placeholder":"Redline attached — 14 changes, and two need your decision:"},
    {"id":"lead-law-early-20","level":"early","profession":"lawyer","title":"The good news you almost buried","scenario":"The insurer just confirmed coverage for the client's defense costs — the issue the client's controller has asked about on every call for a month. Your draft email opens with a recap of the coverage analysis you submitted.","task":"Write a 2-sentence email that leads with the confirmation.","tips":["Good news goes first too — 'Coverage is confirmed.'","Say what it means in dollars or next steps.","The analysis that got you there is for the file, not the lede."],"focus":["clarity","impact"],"placeholder":"Good news — the insurer has confirmed coverage for the defense costs."},
    {"id":"lead-law-early-21","level":"early","profession":"lawyer","title":"The discovery dispute escalation","scenario":"Opposing counsel has now missed the production deadline twice, and you think it's time for a meet-and-confer letter before moving to compel. You want the partner's go-ahead. Your draft chronicles every email exchange since January.","task":"Write a message that leads with your recommendation and the approval you need.","tips":["Sentence one: recommend sending the meet-and-confer letter this week.","The two missed deadlines are your support — one sentence.","End with the specific ask: may I send it?"],"focus":["structure","impact"],"placeholder":"I recommend we send a meet-and-confer letter this week —"},
    {"id":"lead-law-early-22","level":"early","profession":"lawyer","title":"The witness availability problem","scenario":"The client's former CFO — your key witness — just told you he's relocating overseas in six weeks. If his deposition isn't taken before he leaves, scheduling becomes a cross-border problem. Your draft to the partner opens with the history of your contact with him.","task":"Write a 2-3 sentence message that leads with the constraint and the action needed.","tips":["Lead with the six-week window and what closes it.","Name the action: notice his deposition now.","How you learned this is trivia; the deadline is the message."],"focus":["clarity","impact"]},
    {"id":"lead-law-early-23","level":"early","profession":"lawyer","title":"The billing narrative that says nothing","scenario":"The billing partner bounced your time entry — '8.5 hours: work on matter' — and asked for entries the client can read and accept. The work was real: reviewing 900 documents and drafting the deposition outline for the operations witness.","task":"Write 1-2 time-entry narratives that lead with the concrete work product.","tips":["Name the deliverable and the volume: reviewed 900 documents for privilege.","A client should see value in the first five words.","Split distinct tasks into distinct entries."],"focus":["precision","clarity"],"placeholder":"Reviewed 900 client emails for privilege and responsiveness (5.5); drafted deposition outline for"},
    {"id":"lead-law-early-24","level":"early","profession":"lawyer","title":"The meeting you need to ask for","scenario":"You want 20 minutes with your assigning partner to discuss taking a first-chair role at the upcoming preliminary hearing — a stretch assignment you're ready for. Your draft message hedges: 'if you ever have a moment, I'd love to maybe discuss some development stuff.'","task":"Write a request that states the purpose and the time needed up front.","tips":["Name the specific ask: 20 minutes about arguing the preliminary hearing.","Specific requests get calendared; vague ones get deferred.","One sentence of why you're ready, not five."],"focus":["clarity","precision"],"placeholder":"Could I get 20 minutes this week to discuss arguing the Dalton preliminary hearing?"},
    {"id":"lead-law-early-25","level":"early","profession":"lawyer","title":"The two-option decision for the client","scenario":"The client can either accept the landlord's revised terms now or push for a rent abatement and risk losing the space to another bidder. Their COO asked for your take by tomorrow. Your draft spends four paragraphs on lease-market context before presenting the choice.","task":"Write an email opening that leads with the decision, the deadline, and your recommendation.","tips":["Frame it in line one: accept now, or push and risk the space.","State your recommendation — the client hired judgment, not a menu.","Market context earns two sentences, after the decision."],"focus":["structure","impact"],"placeholder":"You have a decision to make by tomorrow: accept the revised terms, or push for abatement and risk losing the space. I recommend"}
  ],
  "start-with-the-audience": [
    {"id":"audience-law-early-01","level":"early","profession":"lawyer","title":"Indemnification, translated","scenario":"The client's operations manager asked what the indemnification clause in the vendor contract actually means for her. Your first draft says the vendor 'shall indemnify, defend, and hold harmless the company from third-party claims arising from vendor's negligence.' She doesn't speak contract.","task":"Write a 2-3 sentence plain-language explanation of what this clause does for her business.","tips":["Translate to consequence: if the vendor causes a problem, they pay, not you.","Use an example she'd recognize — a vendor error that triggers a claim.","Drop the triplet 'indemnify, defend, hold harmless' entirely."],"focus":["audience","clarity"],"placeholder":"In plain terms: if the vendor's mistake gets you sued, they cover the cost —"},
    {"id":"audience-law-early-02","level":"early","profession":"lawyer","title":"Why litigation takes 18 months","scenario":"Your client — a first-time litigant who runs a landscaping company — asked why his contract dispute won't be resolved for 18 months. Your instinct is to walk him through pleadings, discovery, dispositive motions, and trial settings. He wants to know what happens to his business in the meantime.","task":"Write a 3-4 sentence explanation calibrated to what he actually needs to plan around.","tips":["Anchor to his world: when he'll need to be involved and for what.","Name the two or three phases in plain words, with rough dates.","Say what he can keep doing normally in the meantime."],"focus":["audience","clarity"]},
    {"id":"audience-law-early-03","level":"early","profession":"lawyer","title":"The litigation hold, made doable","scenario":"You need the client's HR manager to implement a litigation hold. Your draft says the company must 'suspend routine document destruction and preserve all potentially relevant ESI.' She needs to know what to actually do by Friday.","task":"Write a 3-4 sentence instruction she can act on without calling you back.","tips":["Convert legal duty into concrete steps: stop auto-delete, don't discard files about X.","Name who in her team needs to be told, and what to tell them.","Offer the one-pager; don't make the email carry everything."],"focus":["audience","clarity"],"placeholder":"Starting today, please make sure nothing related to the Harmon project gets deleted —"},
    {"id":"audience-law-early-04","level":"early","profession":"lawyer","title":"Same result, two readers","scenario":"The court denied the other side's motion for summary judgment — meaning the case proceeds to trial. You owe two messages: one to the partner (who wants the court's reasoning) and one to the client's CFO (who wants to know what it costs and when).","task":"Write the first sentence of each message, calibrated to its reader.","tips":["Partner: lead with the holding and the ground the court relied on.","CFO: lead with what it means — trial in the fall, budget implications.","Same fact, different altitude — neither reader gets the other's version."],"focus":["audience","structure"]},
    {"id":"audience-law-early-05","level":"early","profession":"lawyer","title":"Discovery, for someone who's never been sued","scenario":"Your client's day-to-day contact — a warehouse operations lead — just heard the word 'discovery' on a call and asked what it involves for him. He's worried it means something bad about him personally.","task":"Write a 3-4 sentence explanation of discovery pitched to a nervous first-timer.","tips":["Normalize it first: both sides exchange documents in every case like this.","Tell him concretely what he'll be asked to do, and roughly when.","Address the unspoken worry — this isn't about him being in trouble."],"focus":["audience","clarity"],"placeholder":"Discovery is the standard stage where both sides share documents — every case has it."},
    {"id":"audience-law-early-06","level":"early","profession":"lawyer","title":"Force majeure for a bakery owner","scenario":"Your small-business client — a bakery owner — asked whether the force majeure clause protects her if her flour supplier fails again. The clause covers 'acts of God, government action, and events beyond the parties' reasonable control.' She wants a practical answer.","task":"Write a 2-3 sentence answer in her terms, with the honest limits.","tips":["Answer her question first: probably not for a routine supplier failure.","Explain the boundary with her example, not the clause language.","Say what would help instead — a backup-supplier clause next renewal."],"focus":["audience","clarity"]},
    {"id":"audience-law-early-07","level":"early","profession":"lawyer","title":"The memo summary the partner will actually read","scenario":"You wrote twelve pages on whether the client can enforce the arbitration clause against a non-signatory. The partner will read the first paragraph now and the rest on the plane. The analysis is genuinely mixed: two theories work, one is stronger in this circuit.","task":"Write a 3-4 sentence summary paragraph pitched at a partner who knows the case but not your research.","tips":["Lead with the practical answer: yes, most likely, via the estoppel theory.","Give the partner the confidence level and the main risk.","Don't re-teach doctrine the partner knows — calibrate up."],"focus":["audience","structure"],"placeholder":"Most likely yes — the estoppel theory gives us the strongest path in this circuit."},
    {"id":"audience-law-early-08","level":"early","profession":"lawyer","title":"The paralegal briefing without shorthand","scenario":"A paralegal new to the matter is pulling exhibits for the injunction hearing. Your draft asks for 'the usual set, like the Rowan hearing, plus the docs from the March production.' She wasn't on the Rowan matter and has no idea what the March production contains.","task":"Rewrite the request so someone with zero matter history can execute it.","tips":["Spell out the shorthand: name each document type and date range.","Say what the exhibits are for — context catches errors.","One numbered list beats three clarifying phone calls."],"focus":["audience","precision"]},
    {"id":"audience-law-early-09","level":"early","profession":"lawyer","title":"'Without prejudice,' in plain English","scenario":"Your client's managing director saw 'without prejudice' on your settlement letter and asked, half-joking, whether you're insulting the other side. He needs to understand why the label matters before he forwards anything.","task":"Write a 2-3 sentence explanation of what the label does and the one rule he must follow.","tips":["Lead with the function: it keeps settlement talk from being used against us in court.","Give him the rule: don't forward or quote it outside this thread.","Skip the doctrine; he needs the behavior, not the history."],"focus":["audience","clarity"],"placeholder":"It's a protective label, not an insult — it means these settlement discussions can't be used as evidence"},
    {"id":"audience-law-early-10","level":"early","profession":"lawyer","title":"Redlines for the sales lead","scenario":"You've marked up the client's customer contract and need their sales lead to understand the changes before his renewal call tomorrow. Your draft lists edits by section number: '4.2 revised, 7.1(b) deleted, 9.3 new carve-out.' He thinks in deals, not section numbers.","task":"Write a 3-4 sentence summary of the redlines framed around what changes for his deal.","tips":["Translate each change into deal impact: what he can now offer or must hold firm on.","Group by his conversation, not by contract order.","Flag the one term he cannot concede on the call."],"focus":["audience","clarity"],"placeholder":"Three things change for your renewal call: you can now offer quarterly payment terms,"},
    {"id":"audience-law-early-11","level":"early","profession":"lawyer","title":"'Can they actually sue us?'","scenario":"The client's founder forwarded a demand letter from a former contractor and asked one question: 'Can he actually sue us?' Your honest read: yes he can file, but the claim looks weak and is capped by his contract. Your draft opens with a survey of the claims alleged.","task":"Write a 2-3 sentence reply that answers her actual question at her altitude.","tips":["Answer the real worry: anyone can file; whether it goes anywhere is the question.","Give your read on strength in one plain sentence.","End with what happens next, so she isn't left hanging."],"focus":["audience","clarity"],"placeholder":"Yes, he can file — but based on the contract, his claim looks weak and his damages are capped."},
    {"id":"audience-law-early-12","level":"early","profession":"lawyer","title":"The statute turned into a to-do list","scenario":"A new privacy regulation applies to your client's e-commerce business starting next quarter. Your research memo quotes the statutory text at length. The client's one-person compliance 'team' — the office manager — needs to know what to actually change.","task":"Write a 3-4 sentence summary that converts the requirement into actions with dates.","tips":["Lead with the deadline and the one-sentence gist of the rule.","Convert each obligation into a verb: update the privacy notice, add the opt-out link.","Save the statutory citations for the memo footnotes."],"focus":["audience","structure"]},
    {"id":"audience-law-early-13","level":"early","profession":"lawyer","title":"The limitation period that isn't abstract","scenario":"Your client wants to 'wait and see' before pursuing their unpaid-invoice claim. The limitation period expires in seven months, and building the case takes at least two. Your draft explains the doctrine of limitations generally.","task":"Write a 2-3 sentence explanation that makes the deadline real in the client's terms.","tips":["Convert the doctrine to a date: after October, the claim is gone for good.","Work backward out loud: filing takes two months, so the real decision date is August.","Make the cost of waiting concrete — the money becomes uncollectable."],"focus":["audience","impact"],"placeholder":"Here's the practical deadline: if we haven't filed by October, the claim expires permanently —"},
    {"id":"audience-law-early-14","level":"early","profession":"lawyer","title":"Onboarding the new associate","scenario":"A new associate joins the Keller matter Monday and you're writing the orientation note. Your draft references 'the usual dispute about the earn-out,' 'the schedule fight,' and 'what happened with the first mediator' — shorthand from eight months of history she doesn't have.","task":"Write a 3-4 sentence orientation that assumes zero matter knowledge.","tips":["One sentence each: who the parties are, what the fight is about, where it stands.","Expand every piece of shorthand or cut it.","Tell her where the key documents live and what to read first."],"focus":["audience","structure"]},
    {"id":"audience-law-early-15","level":"early","profession":"lawyer","title":"E-discovery costs, justified","scenario":"The client's finance contact flagged the e-discovery vendor invoice — $18,000 this month — and asked why document processing costs so much. Your draft explains data ingestion, deduplication, and hosting fees per gigabyte. He wants to know if this is normal and when it ends.","task":"Write a 3-4 sentence reply pitched at a finance reader's real questions.","tips":["Answer his implied questions first: yes it's in line, and it ends in March.","Give one comparison that anchors 'normal' — cost per document or vs. attorney review.","Technology explanations only where they justify a number."],"focus":["audience","precision"]},
    {"id":"audience-law-early-16","level":"early","profession":"lawyer","title":"The arbitration clause tradeoff","scenario":"Your startup client asked whether to accept the arbitration clause their big customer wants in the master agreement. Your draft explains arbitral procedure. The founder's real question: is this good or bad for a company our size?","task":"Write a 2-3 sentence answer framed around the tradeoff for a small company.","tips":["Lead with your bottom line for them: usually acceptable, and here's the tradeoff.","Frame both sides in their terms: faster and private, but limited appeal and real filing fees.","End with what you'd negotiate — the seat or cost-sharing — not a treatise."],"focus":["audience","clarity"],"placeholder":"For a company your size, this clause is acceptable with one change —"},
    {"id":"audience-law-early-17","level":"early","profession":"lawyer","title":"Why we need their documents","scenario":"The client's engineering lead keeps deprioritizing your request for the project change-orders — he doesn't see why lawyers need engineering paperwork. The documents are central: they show the other side approved the design changes they're now suing over.","task":"Write a 2-3 sentence request that connects his documents to his stake in the outcome.","tips":["Show him the link: his change-orders prove the other side approved the work.","Make the stake his, not yours: this is the evidence that defends his project.","Keep the ask specific — which orders, what date range, by when."],"focus":["audience","impact"],"placeholder":"Those change-orders are the strongest evidence we have that their team approved the design —"},
    {"id":"audience-law-early-18","level":"early","profession":"lawyer","title":"The hearing result in voicemail length","scenario":"The client's owner is traveling and asked for hearing results by voicemail — she'll listen between flights. The result: the judge kept the injunction in place but narrowed it, so the client can resume online sales but not in-store. You have 30 seconds.","task":"Write a 30-second voicemail script that gives her exactly what she can and can't do.","tips":["Lead with the operational answer: online sales can resume today.","Then the boundary: in-store stays paused until the ruling.","End with the next touchpoint; details wait for the follow-up email."],"focus":["audience","concision"],"placeholder":"Quick result from this morning: you can resume online sales today —"},
    {"id":"audience-law-early-19","level":"early","profession":"lawyer","title":"The confidentiality talk with marketing","scenario":"The client's marketing manager wants to announce the acquisition on social media the day of signing. The agreement bars any announcement until closing, roughly six weeks later. She sees legal as the department of no.","task":"Write a 3-4 sentence message that explains the restriction in her terms and gives her something to work with.","tips":["Lead with what she CAN do: prepare everything now, publish at closing.","Explain the why in her language — announcing early can blow up the deal itself.","Offer partnership: you'll pre-clear the copy so it launches the same hour."],"focus":["audience","impact"]},
    {"id":"audience-law-early-20","level":"early","profession":"lawyer","title":"The deposition explained to the witness","scenario":"A client employee — a payroll administrator who has never seen the inside of a courtroom — will be deposed next month. Your draft prep note describes objections, the court reporter, and errata sheets. Her actual questions: what is this, how long, can I get in trouble?","task":"Write a 3-4 sentence first note that answers her real questions and lowers the temperature.","tips":["Define it in one sentence: an interview under oath, in a conference room, no judge.","Answer the fear directly: telling the truth cannot get her in trouble.","Logistics she cares about: how long, who's there, prep session first."],"focus":["audience","clarity"],"placeholder":"A deposition is an interview under oath in a conference room — no judge, no courtroom."},
    {"id":"audience-law-early-21","level":"early","profession":"lawyer","title":"Escrow, for the first-time buyer","scenario":"Your client is buying a small business and asked why $150,000 of the purchase price sits in escrow for a year. Your draft explains indemnity escrows generically. He wants to know: is my money safe, and when do I get certainty this deal is done?","task":"Write a 2-3 sentence explanation anchored to his two real questions.","tips":["Answer the anxiety first: the deal is done at closing; the escrow is the seller's money held back, not his.","Explain the purpose with one concrete example — an undisclosed tax bill surfacing.","Give the date the escrow releases and what could delay it."],"focus":["audience","clarity"]},
    {"id":"audience-law-early-22","level":"early","profession":"lawyer","title":"The heretofore purge","scenario":"You inherited a client letter template that reads: 'Pursuant to the aforementioned agreement and notwithstanding anything herein to the contrary, the undersigned hereby confirms receipt of the heretofore referenced documents.' The client is a plumbing company.","task":"Rewrite the sentence in plain professional English without losing its meaning.","tips":["Every 'aforementioned' and 'heretofore' has a plain replacement or no function.","Read it aloud — if you wouldn't say it to the client, don't write it.","Plain language is not less precise; it's more checkable."],"focus":["audience","concision"],"placeholder":"We confirm we received the documents listed in the March 4 agreement."},
    {"id":"audience-law-early-23","level":"early","profession":"lawyer","title":"One thread, two readers","scenario":"The partner forwarded a client email thread and asked you to 'respond to both' — the client's CEO wants to know if the deal can close this quarter; the partner wants to know if the disclosure schedules are actually finished. One reply will be read by both.","task":"Write a 3-4 sentence reply that serves the CEO as primary reader without misleading the partner.","tips":["Pick the primary audience — the client — and answer their question first.","Carry the partner's detail in one precise sentence the CEO can skim.","Never write two contradictory messages in one email."],"focus":["audience","structure"]},
    {"id":"audience-law-early-24","level":"early","profession":"lawyer","title":"The compliance training pitch to floor staff","scenario":"After a near-miss complaint, the client asked you to write the note announcing mandatory anti-harassment training to warehouse staff. Your draft cites the legal exposure and regulatory framework. The audience is forklift operators reading on their phones at shift change.","task":"Write a 2-3 sentence announcement in the audience's language that gets them to show up.","tips":["Lead with logistics: what, when, how long, paid time.","One sentence of why that respects them — no statute citations.","Reading level: phone screen at shift change."],"focus":["audience","concision"]},
    {"id":"audience-law-early-25","level":"early","profession":"lawyer","title":"The board-altitude paragraph","scenario":"The client's general counsel needs one paragraph on the litigation for her board pack. Your draft covers motion practice, discovery disputes, and scheduling orders. The board needs: exposure range, trajectory, and whether anything requires their decision.","task":"Write a 3-4 sentence board-ready paragraph at the right altitude.","tips":["Board altitude: money, risk direction, decisions needed — nothing procedural.","One number: the current exposure range.","Say explicitly if no board action is needed; that's information too."],"focus":["audience","precision"],"placeholder":"Exposure remains in the $2-3M range and has not changed materially this quarter."}
  ],
  "structure-that-carries": [
    {"id":"structure-law-early-01","level":"early","profession":"lawyer","title":"Six cases, one governing idea","scenario":"Your enforceability research surfaced six relevant cases: four support the client, two cut against. Your draft memo summarizes each case in the order you found them. The partner needs one governing conclusion with the authority organized underneath it.","task":"Write the governing sentence plus the 2-3 bucket labels you'd organize the cases under.","tips":["One roof: the clause is likely enforceable despite two adverse cases.","Buckets by argument, not by date found: supporting authority / adverse cases and why they're distinguishable.","Every case must sit under a bucket; no orphans."],"focus":["structure","clarity"],"placeholder":"The clause is likely enforceable. Supporting that: (1) four decisions in this district enforce"},
    {"id":"structure-law-early-02","level":"early","profession":"lawyer","title":"SCQA for the motion memo","scenario":"You're recommending the client move to dismiss the conversion claim. Your draft opens with the procedural history. Try SCQA instead: the Situation the partner knows, the Complication that changed, the Question it raises, and your Answer.","task":"Write a 4-sentence SCQA opening for the memo.","tips":["Situation: one sentence of what's stable and agreed.","Complication: the new fact — plaintiff's amended complaint added a conversion claim.","Question and Answer: should we move to dismiss it? Yes, because it duplicates the contract claim."],"focus":["structure","clarity"],"placeholder":"The amended complaint adds a conversion claim to the existing contract dispute."},
    {"id":"structure-law-early-03","level":"early","profession":"lawyer","title":"PREP for the hallway question","scenario":"The partner catches you at the elevator: 'Where are we on discovery in Fairmont?' You know everything but tend to answer chronologically, starting with January. Use PREP: Point, Reason, Example, Point.","task":"Write a 4-sentence spoken PREP answer you could say in 30 seconds.","tips":["Point first: we're on track to close discovery March 15 with one open dispute.","Reason and example: productions are complete; the dispute is their withheld financials.","Land the point again with the next step."],"focus":["structure","concision"],"placeholder":"We're on track to close discovery March 15, with one open dispute."},
    {"id":"structure-law-early-04","level":"early","profession":"lawyer","title":"The due-diligence dump, bucketed","scenario":"Your diligence review of the target company produced nine findings: two expired licenses, an unsigned key-employee agreement, a pending customer complaint, missing board minutes, an auto-renewing supplier contract, an unregistered trademark, two customer contracts with change-of-control clauses, and a data-breach notice from 2022. The partner asked for a summary 'that doesn't read like a junk drawer.'","task":"Group the nine findings into 3 labeled buckets and write the one-sentence takeaway for each bucket.","tips":["Bucket by what the client does about them: deal-blockers / fix-before-closing / monitor.","The bucket label should carry a verdict, not a category name.","Nine items, three sentences — the grouping does the compression."],"focus":["structure","clarity"]},
    {"id":"structure-law-early-05","level":"early","profession":"lawyer","title":"The status email skeleton","scenario":"Your weekly update on the Novak matter mixes everything together: a decision the client owes you, three completed tasks, one risk, and two next steps. The client contact reads it on her phone and keeps missing the decision requests.","task":"Rewrite the update using labeled sections — Decisions needed / Progress / Next steps — with one line each.","tips":["The section the reader must act on goes first.","Headings do the navigation so sentences don't have to.","One line per item; detail on request."],"focus":["structure","concision"],"placeholder":"DECISION NEEDED: approval of the revised settlement authority by Thursday."},
    {"id":"structure-law-early-06","level":"early","profession":"lawyer","title":"Three reasons, in order","scenario":"You're drafting the letter asking opposing counsel to consent to a 30-day extension. You have three arguments: their own earlier extension request, the newly produced 12,000 documents, and the upcoming holidays. Your draft mentions each twice in random order.","task":"Write a 3-4 sentence request with the three reasons in deliberate order, strongest first.","tips":["Lead with the ask, then the reasons in ranked order.","Their own prior extension request is the argument they can't reject — it goes first.","Say each reason once; repetition weakens, not strengthens."],"focus":["structure","impact"]},
    {"id":"structure-law-early-07","level":"early","profession":"lawyer","title":"The deposition summary by theme","scenario":"You attended the 6-hour deposition of the opposing project manager. Your notes run chronologically: morning session, lunch, afternoon. The partner needs the summary organized by what matters: admissions, damaging testimony, and credibility observations.","task":"Write the 3 theme headings and one example line under each.","tips":["Chronology is how you experienced it; themes are how the partner uses it.","Lead with the best admission — the reason the summary exists.","Keep credibility observations separate from testimony; they're different kinds of evidence."],"focus":["structure","precision"],"placeholder":"KEY ADMISSIONS: He confirmed no one reviewed the specs before approval."},
    {"id":"structure-law-early-08","level":"early","profession":"lawyer","title":"The contract review, triaged","scenario":"You reviewed the 40-page reseller agreement the client wants to sign. You have 17 comments ranging from a one-sided termination right to typos. The client's business development lead asked what she actually needs to worry about.","task":"Organize your review into 3 tiers — must fix / should negotiate / accept as-is — and write the one-line summary of each tier.","tips":["Triaging is the value; an unranked list of 17 transfers your work to the reader.","Tier one earns its place only if the client should walk without it.","Say how many items are in each tier so the load is visible."],"focus":["structure","audience"]},
    {"id":"structure-law-early-09","level":"early","profession":"lawyer","title":"SCQA for settle-or-fight","scenario":"The client must decide whether to accept the $180,000 settlement offer or proceed toward trial. You're structuring the advice email. The client knows the case; what changed is the offer and the new trial date pushing costs up.","task":"Write a 4-5 sentence SCQA passage ending in your recommendation.","tips":["Situation: the case posture the client already knows — one sentence.","Complication: the offer expires Friday and trial costs just grew.","The Answer is a recommendation with a number, not a description of options."],"focus":["structure","impact"],"placeholder":"The case has been heading to a fall trial with estimated remaining costs of $120,000."},
    {"id":"structure-law-early-10","level":"early","profession":"lawyer","title":"PREP under a hot question","scenario":"In the team meeting, the senior associate asks you directly: 'Should we file in state or federal court?' You researched this. Your instinct is to walk through your research journey. The room needs Point, Reason, Example, Point.","task":"Write a 4-sentence spoken PREP answer.","tips":["Point: federal court, and say it before any analysis.","One reason carries the answer: the likely removal fight makes state court a detour.","Restate the point with the action: I'll draft for federal filing."],"focus":["structure","clarity"],"placeholder":"Federal court. If we file in state court, they'll remove it anyway —"},
    {"id":"structure-law-early-11","level":"early","profession":"lawyer","title":"Twelve questions, one agenda","scenario":"Over three days, the client's operations contact sent you twelve questions across six emails — about the audit clause, insurance certificates, two invoice disputes, the subcontractor approval, and when the amendment gets signed. You're setting up one call to resolve everything.","task":"Write a call agenda that groups the twelve questions into 3-4 logical blocks with time estimates.","tips":["Group by topic and decision-owner, not by which email they arrived in.","Put quick confirmations first to build momentum; the contested invoices get the biggest block.","An agenda is a promise about time — total it and keep it under the hour."],"focus":["structure","concision"]},
    {"id":"structure-law-early-12","level":"early","profession":"lawyer","title":"The closing checklist update","scenario":"Fourteen items remain before Friday's closing. Your draft update lists them in the order they appear on the master checklist. The partner needs to know instantly: what's done, what's on track, and what's at risk — and who owns each open item.","task":"Write the structure of the update: 3 status groups with one item and owner as an example in each.","tips":["Group by status, not checklist order — risk items first.","Every open item gets an owner and a date or it isn't tracked.","The at-risk group is why the partner reads; don't bury it."],"focus":["structure","precision"],"placeholder":"AT RISK (2): payoff letter from the bank — owner: their counsel, promised Wednesday."},
    {"id":"structure-law-early-13","level":"early","profession":"lawyer","title":"The mixed-research governing idea","scenario":"Your research came out genuinely mixed: the client's late notice probably voids the warranty claim, but a consumer-protection theory survives. Your draft presents both threads side by side with no roof over them, and the partner won't know what you concluded.","task":"Write one governing sentence that honestly carries both findings, plus the two bucket labels beneath it.","tips":["Mixed results still need a roof: 'the warranty claim is likely gone, but a narrower path remains.'","The governing idea states the net position, not 'it depends.'","Order the buckets by what the partner will do with them."],"focus":["structure","clarity"],"placeholder":"The warranty claim is likely barred by late notice, but the consumer-protection theory gives us a narrower path."},
    {"id":"structure-law-early-14","level":"early","profession":"lawyer","title":"From chronology to issues","scenario":"Your case summary for the new partner on the matter reads like a diary: March demand letter, April response, May complaint, June answer. She asked for it 'organized by what's actually in dispute' — which is three things: whether notice was given, who owed the maintenance duty, and the damages math.","task":"Write the 3 issue headings and a one-line status under each.","tips":["Issues are the skeleton; dates hang off them, not the reverse.","Each issue line ends with where it stands: contested, conceded, or undeveloped.","The chronology can survive as an appendix."],"focus":["structure","clarity"]},
    {"id":"structure-law-early-15","level":"early","profession":"lawyer","title":"Open items, three buckets","scenario":"Signing is Tuesday. Nine items are open: two consents, three schedule updates, a side letter, the wire instructions, a board resolution, and the employment agreement signature. Your draft email lists all nine in one undifferentiated paragraph to the client's deal lead.","task":"Rewrite as an email with 3 bucketed lists: client to do / other side to do / law firm to do.","tips":["Bucket by owner — the reader should find their list in two seconds.","Deadlines inside each bucket, hardest first.","Nine items in one paragraph guarantees a dropped item."],"focus":["structure","clarity"],"placeholder":"YOUR SIDE (3 items, all by Monday noon):"},
    {"id":"structure-law-early-16","level":"early","profession":"lawyer","title":"Witness notes into a usable shape","scenario":"You spent two hours interviewing the client's former site supervisor. Your raw notes mix solid facts, things he was fuzzy on, and leads to chase. The partner wants them 'in a shape someone can act on' by tomorrow.","task":"Write the 3 section headings you'd use and one example entry under each.","tips":["Separate what he knows, what he's unsure of, and what needs corroboration — mixing them poisons all three.","Fuzzy recollections labeled as fuzzy are useful; unlabeled they're dangerous.","Follow-ups get an owner, or they're just wishes."],"focus":["structure","precision"]},
    {"id":"structure-law-early-17","level":"early","profession":"lawyer","title":"PREP for 'why is this taking so long?'","scenario":"On the monthly call, the client's COO asks — with an edge — why the case is eight months old with no end in sight. You have a good answer: the schedule is normal, and the delay that exists came from the other side's discovery defaults. Structure keeps it from sounding defensive.","task":"Write a 4-sentence spoken PREP answer.","tips":["Point: the case is on the normal schedule for its size, and here's the end date.","Reason with the one real example: their late production cost us the spring window.","End on the point plus what happens next month — forward motion."],"focus":["structure","audience"],"placeholder":"The case is actually on schedule — cases like this run 14 to 18 months, and we're on track for"},
    {"id":"structure-law-early-18","level":"early","profession":"lawyer","title":"Objections, grouped for the fight","scenario":"You're drafting responses to 45 document requests. Your objections cluster naturally: overbreadth on 12 requests, privilege on 6, irrelevance on 9, and 18 you'll produce without a fight. Your draft handles each request in numerical order, re-arguing the same objection twelve times.","task":"Write the internal summary for the partner: the 4 groups, counts, and your one-line rationale per group.","tips":["Group by objection type — the argument gets made once, well.","Lead with what you're producing; it frames the objections as reasonable.","Counts per group let the partner weigh the fight at a glance."],"focus":["structure","concision"]},
    {"id":"structure-law-early-19","level":"early","profession":"lawyer","title":"Five minutes at the partner meeting","scenario":"You've been given five minutes at the practice-group meeting to update twelve partners on the Delgado matter. You could talk for an hour. You need one message and at most three supporting points, or you'll be cut off mid-ramble.","task":"Write your one-sentence message and the three supporting points as you'd say them.","tips":["Choose the single thing twelve partners need: the matter turns on the June mediation.","Three supports maximum — pick the ones that affect other people's work.","Rehearse the first sentence; the room decides in ten seconds whether to listen."],"focus":["structure","concision"],"placeholder":"Everything in Delgado now points at the June mediation — three things to know."},
    {"id":"structure-law-early-20","level":"early","profession":"lawyer","title":"The risk memo frame","scenario":"The client asked what could go wrong if they terminate the distributor now rather than at renewal. You've identified four risks of different sizes. Your draft discusses them in the order you thought of them, with no signal of which ones matter.","task":"Write the memo's organizing frame: each risk stated with likelihood and magnitude, ordered by expected impact.","tips":["A risk without likelihood and size is just a worry.","Order by expected impact — biggest first, not first-thought-of first.","End the frame with the net judgment: terminate now or wait."],"focus":["structure","precision"],"placeholder":"Risk 1 — wrongful termination claim: likely (they've threatened it), exposure $200-400K."},
    {"id":"structure-law-early-21","level":"early","profession":"lawyer","title":"The policy review, themed","scenario":"You reviewed the client's employee handbook against current law and found nine problems: three outdated leave provisions, two missing state-required notices, an unlawful social-media rule, two inconsistent disciplinary sections, and a non-compliant overtime description. The HR director asked 'how bad is it?'","task":"Group the nine findings into 3 themes and write a one-sentence answer to 'how bad is it?' as the opener.","tips":["Answer the actual question first: fixable, mostly routine, two urgent items.","Themes by required action: must fix now / fix this quarter / tidy at next revision.","Nine findings under three roofs reads as competence; a list of nine reads as chaos."],"focus":["structure","audience"]},
    {"id":"structure-law-early-22","level":"early","profession":"lawyer","title":"SCQA for the revised draft","scenario":"You're sending the client's CFO the fourth draft of the loan amendment. What changed since draft three: the bank accepted the covenant carve-out but added a reporting requirement. Your cover email currently says 'please see attached revised draft' and nothing else.","task":"Write a 3-4 sentence SCQA cover note for the draft.","tips":["Situation: where the negotiation stood at draft three.","Complication: what the bank changed — give and take.","Answer: sign-off on the reporting requirement is the one decision left."],"focus":["structure","clarity"],"placeholder":"Draft four is attached. Since the last version, the bank accepted our covenant carve-out —"},
    {"id":"structure-law-early-23","level":"early","profession":"lawyer","title":"The intake, shaped","scenario":"Your pro bono intake interview produced a tangle: the client's landlord issues, a debt collection letter, and a possible wage claim, all mixed together in your notes. The supervising partner will decide which threads the clinic takes based on your one-page summary.","task":"Write the summary structure: 3 matter headings, each with a one-line facts summary and a one-line viability read.","tips":["Three separate legal problems need three separate roofs — untangle before summarizing.","Each thread gets the same two-line treatment: what happened, is there a case.","Rank them: lead with the thread you'd take."],"focus":["structure","clarity"]},
    {"id":"structure-law-early-24","level":"early","profession":"lawyer","title":"The voicemail turned task list","scenario":"The partner left you a 3-minute voicemail on her drive in: check the choice-of-law clause, call the expert about scheduling, something about the exhibit list she'll explain later, and move the client call — it's mixed with commentary about the mediator. You're confirming by email so nothing is lost.","task":"Write a confirmation email that turns the voicemail into a numbered task list with your understanding of each deadline.","tips":["Numbered list — the structure is the confirmation.","Flag the ambiguous item explicitly rather than guessing: 'exhibit list — awaiting your detail.'","State your assumed deadlines so she can correct them cheaply."],"focus":["structure","precision"],"placeholder":"Confirming the four items from your voicemail: 1) Review the choice-of-law clause by"},
    {"id":"structure-law-early-25","level":"early","profession":"lawyer","title":"Questions a partner can answer in one pass","scenario":"You have five open questions on the brief before you can finish: two about strategy, two about formatting conventions, one about whether to address a weak counterargument. Your draft email interleaves them through six paragraphs of context. The partner will answer whatever is easy to find and miss the rest.","task":"Restructure into an email with numbered questions, each answerable in one line, ordered by importance.","tips":["One question per number; never two asks in one sentence.","Give each question its minimum context inline — the partner shouldn't scroll.","Order by decision weight: strategy first, formatting last."],"focus":["structure","concision"]}
  ],
  "cut-to-the-bone": [
    {"id":"concise-law-early-01","level":"early","profession":"lawyer","title":"The hedge-stacked conclusion","scenario":"Your memo conclusion reads: 'It would seem that, based on the foregoing, the court could arguably be somewhat inclined to potentially find that the notice provision may not have been fully satisfied.' The partner circled it and wrote 'so...?'","task":"Rewrite the conclusion in one sentence with a single, deliberate qualifier.","tips":["Stacked hedges cancel each other; keep the one that carries real doubt.","'The court will likely find notice was insufficient' says more with less.","If you can't commit to a direction, say what would resolve the doubt."],"focus":["concision","clarity"],"placeholder":"The court will likely find the notice provision was not satisfied."},
    {"id":"concise-law-early-02","level":"early","profession":"lawyer","title":"The six-sentence update, halved","scenario":"Your client update runs six sentences: a greeting recap, a sentence about how busy the docket is, the actual news (hearing moved to May 2), a sentence explaining court scheduling generally, the impact (deposition timing unaffected), and an offer to discuss. The client contact reads on her phone.","task":"Cut it to three sentences without losing information she needs.","tips":["The news and the impact are the email; most of the rest is packaging.","Court-scheduling context survives only if it answers a question she'd actually ask.","'Happy to discuss' earns its place; the busy-docket sentence doesn't."],"focus":["concision","clarity"],"placeholder":"The hearing has moved to May 2. Your deposition dates are unaffected."},
    {"id":"concise-law-early-03","level":"early","profession":"lawyer","title":"The nominalization sweep","scenario":"Your draft letter says the client 'will effectuate the termination of the agreement and make provision for the return of all deliverables upon the occurrence of the expiration date.' Every action is buried in a noun.","task":"Rewrite the sentence with verbs doing the work.","tips":["'Effectuate the termination of' is 'terminate.'","'Make provision for the return of' is 'return.'","Nouns hide actors; verbs expose who does what — which is the legal point."],"focus":["concision","clarity"],"placeholder":"The client will terminate the agreement and return all deliverables when it expires."},
    {"id":"concise-law-early-04","level":"early","profession":"lawyer","title":"The memo that narrates itself","scenario":"Your memo opens: 'This memorandum will first address the statutory framework, then discuss the relevant case law, and finally analyze the application to our facts before offering a conclusion.' A paragraph about the memo, before the memo.","task":"Delete the meta-commentary and write the opening sentence that does the work instead.","tips":["Describing your structure is not the same as having one — headings show structure.","The first sentence should carry a conclusion, not a table of contents.","If the roadmap sentence vanished, the reader would lose nothing."],"focus":["concision","structure"],"placeholder":"The client can recover the deposit: the statute requires written notice, and none was given."},
    {"id":"concise-law-early-05","level":"early","profession":"lawyer","title":"The redundant pairs letter","scenario":"The client termination letter you inherited declares the agreement 'null and void,' demands 'each and every' deliverable, requires 'full and complete' payment, and reserves 'any and all' rights. The client asked why lawyers say everything twice.","task":"Rewrite the letter's key sentence keeping one word from each pair.","tips":["'Void,' 'every,' 'full,' 'all' — the second word adds history, not meaning.","Doubled words invite the question of what the difference is; single words don't.","Precision is choosing the right word once."],"focus":["concision","precision"]},
    {"id":"concise-law-early-06","level":"early","profession":"lawyer","title":"The 200-word email to opposing counsel","scenario":"Your draft to opposing counsel about a deposition date runs 200 words: pleasantries, a recap of prior correspondence, the availability conflict, three alternative dates, a paragraph reserving rights, and a closing flourish. Everything they need fits in three sentences.","task":"Cut the email to 3 sentences that preserve the substance and the professional tone.","tips":["Opposing counsel reads for commitments and dates; give them cleanly.","Reserving rights in a scheduling email is reflex, not necessity.","Courtesy survives compression — one 'thanks' beats three formalities."],"focus":["concision","clarity"],"placeholder":"We can't make the 14th. We can offer April 21, 22, or 28 —"},
    {"id":"concise-law-early-07","level":"early","profession":"lawyer","title":"The filler-free phone update","scenario":"You're about to call the partner with a discovery update. Your rehearsal is full of filler: 'so basically,' 'kind of,' 'I just wanted to touch base,' 'at the end of the day.' The substance is one sentence: the vendor finished processing and review starts Monday.","task":"Write the 2-sentence spoken update with the filler stripped out.","tips":["'I just wanted to' delays every sentence it starts — delete it.","Silence between sentences reads as confidence; filler reads as nerves.","Say the update aloud once; cut whatever you stumbled over."],"focus":["concision","clarity"],"placeholder":"Quick update: the vendor finished processing overnight."},
    {"id":"concise-law-early-08","level":"early","profession":"lawyer","title":"The discovery report on a diet","scenario":"Your weekly discovery report to the partner is a page long, but the content is: review is 60% complete, on pace for the deadline, 14 hot documents flagged, one custodian's files delayed to Thursday. Everything else is restated methodology.","task":"Rewrite the report as 3-4 lines carrying only the numbers and the exception.","tips":["Recurring reports earn brevity — the reader knows the methodology.","Numbers plus the one exception is the whole job.","If a sentence would appear unchanged in every weekly report, cut it."],"focus":["concision","precision"],"placeholder":"Review 60% complete, on pace for the 4/30 deadline. 14 hot documents flagged this week —"},
    {"id":"concise-law-early-09","level":"early","profession":"lawyer","title":"One line, not one paragraph","scenario":"The client's project manager asked whether the NDA covers their subcontractors. It does — Section 8 extends it to 'representatives,' which is defined to include subcontractors. Your draft reply explains the definition section's architecture across a full paragraph.","task":"Write the reply in 1-2 sentences.","tips":["Yes, plus where it says so, is the complete answer.","The definitional chain is for the file memo, not the client email.","Confidence is short; anxiety writes paragraphs."],"focus":["concision","clarity"],"placeholder":"Yes — the NDA covers your subcontractors."},
    {"id":"concise-law-early-10","level":"early","profession":"lawyer","title":"'Please be advised' and friends","scenario":"The firm's old notice template opens: 'Please be advised that pursuant to the terms of your agreement, we hereby wish to inform you that the following matter requires your attention at your earliest convenience.' Forty-two words before any content.","task":"Rewrite the opening so the first sentence delivers actual information.","tips":["'Please be advised that' advises nothing — start where the content starts.","'Hereby wish to inform you' is the same ghost twice.","'At your earliest convenience' means nothing; a date means something."],"focus":["concision","impact"]},
    {"id":"concise-law-early-11","level":"early","profession":"lawyer","title":"The deposition summary paragraph, tightened","scenario":"Your summary paragraph: 'During the course of the deposition, the witness indicated on multiple occasions that she did not have any specific recollection of having attended the meeting in question, notwithstanding the fact that her name appears on the attendance list that was circulated.' Fifty words for a twenty-word fact.","task":"Rewrite in 20 words or fewer without losing the tension.","tips":["'During the course of' is 'during'; 'notwithstanding the fact that' is 'although.'","The interesting part is the contradiction — make it the spine of the sentence.","Shorter makes the contradiction sharper, which is the point of reporting it."],"focus":["concision","precision"],"placeholder":"She testified she doesn't recall the meeting, although the attendance list includes her name."},
    {"id":"concise-law-early-12","level":"early","profession":"lawyer","title":"The throat-clearing intro","scenario":"Your research memo opens with three sentences on the general importance of employment law, two on the history of the at-will doctrine, and one thanking the partner for the interesting question — before the question presented appears.","task":"Delete the throat-clearing and write the sentence the memo should start with.","tips":["Start where the partner's knowledge ends, not where the textbook begins.","Nobody assigned you the history of the doctrine.","The compliment to the question is billable throat-clearing."],"focus":["concision","structure"],"placeholder":"The client can likely terminate without severance obligation, with one exception."},
    {"id":"concise-law-early-13","level":"early","profession":"lawyer","title":"The timeline, compressed","scenario":"Your chronology section recites eleven dates: contract signed, first delivery, first complaint, each email exchanged, the demand letter, the response. Only three dates carry legal weight: the delivery, the complaint deadline in the contract, and when the client actually complained — six weeks late.","task":"Write a 2-3 sentence chronology that carries only the dates that decide the issue.","tips":["A chronology argues; it doesn't archive — pick the dates that do work.","The gap between deadline and action IS the story; put the six weeks in one sentence.","The full eleven dates can live in a table if anyone asks."],"focus":["concision","impact"],"placeholder":"The contract required complaints within 10 days of delivery. Delivery was March 3; the client first complained April 19 —"},
    {"id":"concise-law-early-14","level":"early","profession":"lawyer","title":"The clear answer, unqualified","scenario":"Your research is unambiguous: the statute plainly requires the disclosure and every court to consider it agrees. Your draft still says the requirement 'appears to potentially apply' and the cases 'seem to suggest' the obligation 'may be mandatory.' The hedges are habit, not analysis.","task":"Rewrite the 2-sentence conclusion to match the actual strength of the law.","tips":["Calibration cuts both ways — hedging a certain answer is as wrong as overclaiming a weak one.","'The statute requires disclosure' when it does is precision, not bravado.","Save qualifiers for the parts that are genuinely uncertain, and name why."],"focus":["concision","precision"],"placeholder":"The statute requires the disclosure. Every court to address the question has enforced it."},
    {"id":"concise-law-early-15","level":"early","profession":"lawyer","title":"The billing entry the client will pay","scenario":"Your time entry reads: 'Attention to various matters in connection with ongoing discovery issues and related correspondence regarding same; review of documents in connection therewith (3.2).' The billing partner says the client rejects entries like this on sight.","task":"Rewrite as 1-2 entries that name the actual work in plain words.","tips":["'Attention to various matters' describes every hour ever billed — name the task.","'Regarding same / in connection therewith' are padding with a law degree.","A payable entry names the document, the counterparty, or the deliverable."],"focus":["concision","precision"],"placeholder":"Drafted responses to plaintiff's second document requests (2.1); emails with opposing counsel re"},
    {"id":"concise-law-early-16","level":"early","profession":"lawyer","title":"The talking points, halved","scenario":"You prepared ten talking points for the partner's fifteen-minute client call. She glanced at them and said 'I'll get through four.' The call must cover the settlement posture, the new hearing date, the invoice question, and the document request — the rest was you being thorough.","task":"Cut the list to the 4 essential points, one line each.","tips":["Match the artifact to the container: fifteen minutes is four points.","Each point is a headline she can say, not a paragraph she must parse.","Being thorough on paper is often being unusable in the room."],"focus":["concision","audience"]},
    {"id":"concise-law-early-17","level":"early","profession":"lawyer","title":"The passive-voice incident report","scenario":"Your summary of the missed deadline reads: 'It was determined that the filing deadline had been miscalendared, and the error was not discovered until the deadline had already passed. Corrective measures are being implemented.' Nobody in the paragraph did anything.","task":"Rewrite in active voice, naming actors, in 2 sentences.","tips":["Passive voice in incident reports reads as evasion — name who found it and who's fixing it.","'Corrective measures are being implemented' means nothing; 'we now double-enter deadlines' means something.","Owning the error in active voice is what actually rebuilds trust."],"focus":["concision","clarity"],"placeholder":"The paralegal team calendared the deadline for the wrong month, and I caught it the day after it passed."},
    {"id":"concise-law-early-18","level":"early","profession":"lawyer","title":"The two-sentence cover email","scenario":"You're sending the client the revised employment agreement. Your draft cover email is nine sentences: a recap of the negotiation, a description of each change, thoughts on the counterparty's motives, and finally what you need — their signature by Friday.","task":"Write the cover email in 2 sentences.","tips":["A cover email covers; it doesn't recap the engagement.","What's attached, what changed in one clause, what you need by when.","The negotiation retrospective is a call if they want it."],"focus":["concision","clarity"],"placeholder":"Revised agreement attached — the only change from Tuesday's version is the notice period (now 60 days). Please sign by Friday."},
    {"id":"concise-law-early-19","level":"early","profession":"lawyer","title":"The wall of caveats","scenario":"Your advice email carries five disclaimers: the analysis is preliminary, based on documents provided, subject to local counsel confirmation, dependent on facts as described, and not addressing tax. Only the tax carve-out actually matters here — the client asked a tax-adjacent question.","task":"Rewrite keeping only the caveat that does real work, integrated naturally.","tips":["Five caveats read as one big 'don't rely on me' — which defeats the email.","Keep the caveat that changes what the reader does next.","Put it where it's relevant, not in a wall at the end."],"focus":["concision","audience"],"placeholder":"One flag: this doesn't cover the tax treatment — worth a quick call with your accountant before"},
    {"id":"concise-law-early-20","level":"early","profession":"lawyer","title":"The exhibit chase, shortened","scenario":"Your third email chasing the client for the two missing signed change-orders runs six sentences of softening: you understand they're busy, you hate to keep asking, whenever convenient. The arbitration exhibit deadline is in five days.","task":"Rewrite as a 2-sentence request with the deadline doing the motivating.","tips":["The deadline is kinder than the apologies — it explains the urgency.","Name the two documents precisely so the reply can be one attachment.","Offer the escape hatch: if they can't find them, say so today so you can plan."],"focus":["concision","impact"],"placeholder":"I need the two signed change-orders (Nos. 4 and 7) by Thursday — our exhibit deadline is Monday."},
    {"id":"concise-law-early-21","level":"early","profession":"lawyer","title":"The subject line that works","scenario":"Your email to the client contact is important — it needs her approval of the settlement authority by Thursday — but the subject line reads 'Update.' It will sit unopened beneath forty others.","task":"Write a subject line that carries the ask and the deadline.","tips":["The subject line is the first sentence of the email, not a label.","'Approval needed by Thu: settlement authority' survives the inbox.","If the subject does its job, the email body can be two sentences."],"focus":["concision","impact"],"placeholder":"Approval needed by Thursday: settlement authority increase"},
    {"id":"concise-law-early-22","level":"early","profession":"lawyer","title":"The thread reply that re-explains everything","scenario":"You're replying on a 14-message thread with the client and the partner about the license renewal. Your draft re-summarizes the whole thread before adding your one new fact: the licensor agreed to the fee cap. Everyone on the thread has read the thread.","task":"Write the reply carrying only the new information and its consequence.","tips":["A thread reply owes the thread only what's new.","One sentence of news, one of consequence: we can sign as drafted.","Re-summarizing signals you don't trust the reader — or your own point."],"focus":["concision","clarity"],"placeholder":"The licensor just agreed to the fee cap. That was the last open item —"},
    {"id":"concise-law-early-23","level":"early","profession":"lawyer","title":"The negotiation call recap","scenario":"Your recap of the 90-minute negotiation call runs a full page of who-said-what. What the partner and client need: agreement on the royalty rate (4%), deadlock on the exclusivity term, and the other side's promise to send revised language by Tuesday.","task":"Write the recap in 3 sentences: agreed, open, next.","tips":["Recaps exist so people can act, not relive the call.","Three states cover everything: agreed, open, and who owes what by when.","The who-said-what belongs in your notes, available on request."],"focus":["concision","structure"],"placeholder":"Agreed: 4% royalty. Still open: the exclusivity term —"},
    {"id":"concise-law-early-24","level":"early","profession":"lawyer","title":"The twenty-second voicemail","scenario":"You need to leave the client's CFO a voicemail: the auditor's confirmation letter is fine to sign, with one date corrected. Your rehearsed version runs ninety seconds with a recap of what the letter is and why auditors send them. He knows — he sent it to you.","task":"Write a voicemail script of 20 seconds or less.","tips":["He needs the verdict, the one correction, and where the details are.","Don't explain his own document to him.","End with the redundancy: 'details in my email' — voicemail plus email is the reliable channel pair."],"focus":["concision","audience"],"placeholder":"It's fine to sign with one fix — the response deadline should be March 15, not March 5."},
    {"id":"concise-law-early-25","level":"early","profession":"lawyer","title":"The paragraph that announces itself","scenario":"Your memo's analysis section opens: 'Before turning to the application of the case law to the facts at hand, it is first necessary to briefly summarize the relevant factual background that gives rise to the issues discussed herein.' Then the facts begin.","task":"Delete the announcement and write the sentence that starts the facts directly.","tips":["'It is first necessary to summarize' — so summarize; the announcement is scaffolding.","Readers know facts are background; labeling them 'relevant' adds nothing.","Cut every sentence about the document from the document."],"focus":["concision","structure"],"placeholder":"The client signed the lease in June 2023, four months before the zoning change."}
  ],
  "precision-and-evidence": [
    {"id":"precision-law-early-01","level":"early","profession":"lawyer","title":"'Strong case' means what, exactly","scenario":"Your draft memo tells the partner the client 'has a strong case' on the breach claim. The partner writes back: 'Strong how? Give me something I can tell the client.' You actually have specifics — three of the four elements are undisputed and only causation is contested.","task":"Rewrite the assessment replacing 'strong' with the concrete facts behind it.","tips":["'Strong' is a conclusion; the partner wants the evidence that earned it.","Name what's undisputed and what's the single fight — that's the shape of the case.","A skeptic should be able to check your claim against the record."],"focus":["precision","clarity"],"placeholder":"Three of the four breach elements are undisputed; only causation is genuinely contested —"},
    {"id":"precision-law-early-02","level":"early","profession":"lawyer","title":"'Soon' isn't a date","scenario":"Your status email tells the client the disclosure schedules will be 'done soon' and the deal should close 'shortly thereafter.' The client's CFO needs dates for his board. You know the real answer: schedules by Thursday, closing targeted for the 20th.","task":"Rewrite the two sentences replacing every vague time word with a date.","tips":["'Soon' and 'shortly' are what you say when you don't want to commit — commit.","If a date has a condition, state the condition, not a fog word.","A date can be missed and explained; 'soon' can only erode trust."],"focus":["precision","clarity"],"placeholder":"The disclosure schedules will be final by Thursday, with closing targeted for the 20th."},
    {"id":"precision-law-early-03","level":"early","profession":"lawyer","title":"The exposure number, not a shrug","scenario":"The client asked what the lawsuit could cost if it goes badly. Your draft says 'it could be significant.' You've actually run the numbers: contract damages are capped at $400K, plus roughly $150K in fees to trial. 'Significant' throws away your analysis.","task":"Write a 2-3 sentence exposure estimate with the numbers and their basis.","tips":["Replace 'significant' with a range and where each figure comes from.","Separate what's capped by contract from what's open-ended — the client needs both.","Give the assumption behind the fee estimate so it's checkable, not magic."],"focus":["precision","impact"],"placeholder":"Worst realistic case is roughly $550K: contract damages capped at $400K, plus about $150K in fees through trial."},
    {"id":"precision-law-early-04","level":"early","profession":"lawyer","title":"From 'lots of documents' to a count","scenario":"You're updating the partner on the review and say 'we've gone through a lot of the documents.' She needs to staff the next two weeks. The real numbers: 32,000 of 55,000 reviewed, 210 flagged as responsive, 14 as hot.","task":"Rewrite the update carrying the counts and what they imply for staffing.","tips":["'A lot' can't be planned against; 32,000 of 55,000 can.","Pair the raw count with the rate — it forecasts the finish.","The hot-document count is the number the partner actually cares about — lead toward it."],"focus":["precision","impact"],"placeholder":"We've reviewed 32,000 of 55,000 documents (58%), flagging 210 responsive and 14 hot —"},
    {"id":"precision-law-early-05","level":"early","profession":"lawyer","title":"So what, and now what","scenario":"Your memo reports that the contract was signed by the VP of Sales, not an officer with signing authority under the corporate bylaws. You state the fact and stop. The partner needs the So What (the contract may be unauthorized) and the Now What (whether the client ratified it).","task":"Write 3 sentences: the fact, its legal consequence, and the next step to pin it down.","tips":["A fact without a 'so what' makes the reader do your analysis.","So what: the signature may not bind the counterparty.","Now what: check whether later performance ratified it — name the documents to pull."],"focus":["precision","structure"],"placeholder":"The contract was signed by the VP of Sales, not an authorized officer. That means the counterparty may argue it isn't bound —"},
    {"id":"precision-law-early-06","level":"early","profession":"lawyer","title":"'The witness was evasive'","scenario":"Your deposition summary says the opposing witness 'was evasive and not credible.' The partner will use this to plan cross — she needs the specifics that support the characterization, not the label. You have them: three 'I don't recall' answers on documents bearing his signature.","task":"Rewrite replacing the characterization with the specific testimony that shows it.","tips":["'Evasive' is your conclusion; the partner wants the transcript facts that prove it.","Cite the moment: which questions, which documents, what he claimed not to recall.","Let the reader reach 'evasive' from the facts — it lands harder than the label."],"focus":["precision","clarity"],"placeholder":"He answered 'I don't recall' to three questions about emails he personally signed —"},
    {"id":"precision-law-early-07","level":"early","profession":"lawyer","title":"The percentage that needs a denominator","scenario":"You tell the partner the client 'wins most of these motions.' She asks 'most, based on what?' Your research found that in this district, courts granted this motion type in 8 of the last 11 published rulings — a real basis you flattened into 'most.'","task":"Rewrite the claim with the actual ratio and its source.","tips":["'Most' hides the sample; 8 of 11 shows your work.","Name where the sample comes from — this district, published rulings, last five years.","A ratio invites the partner to trust the number; 'most' invites her to doubt it."],"focus":["precision","clarity"],"placeholder":"In this district, courts granted this motion in 8 of the last 11 published rulings —"},
    {"id":"precision-law-early-08","level":"early","profession":"lawyer","title":"The risk, quantified two ways","scenario":"You're flagging a risk in the acquisition: the target has one customer worth 40% of revenue, and that contract can be terminated on 30 days' notice. Your draft calls it 'a concerning concentration risk' without the two numbers that make it concrete.","task":"Write a 2-3 sentence flag carrying both the concentration figure and the termination exposure.","tips":["'Concerning' is a feeling; 40% of revenue on 30 days' notice is a fact the buyer can price.","Two numbers do the persuading — the share and the notice period.","End with what it means for the deal: a price adjustment or a retention condition."],"focus":["precision","impact"],"placeholder":"One customer is 40% of the target's revenue, and its contract terminates on 30 days' notice —"},
    {"id":"precision-law-early-09","level":"early","profession":"lawyer","title":"The skeptic test on a citation","scenario":"Your brief argues a point and cites a case for it. Reading again, you realize the case supports a related but narrower proposition — it's about oral contracts, and you're citing it for written ones. A skeptical clerk would catch the gap instantly.","task":"Write a 2-sentence note to the partner flagging the stretch and proposing the fix.","tips":["Test every citation as an opponent would: does it actually say what you claim?","Name the gap precisely — the holding is about oral contracts, our facts are written.","Propose the fix: a better case, or narrowing the claim to what the case supports."],"focus":["precision","clarity"]},
    {"id":"precision-law-early-10","level":"early","profession":"lawyer","title":"'Recently' and 'a while ago'","scenario":"Your factual summary says the client complained 'recently' and the defect appeared 'a while before that.' For a limitations analysis, the exact dates decide the case. You have them: complaint on April 19, defect first noted March 3.","task":"Rewrite the timeline sentence with exact dates and the gap between them.","tips":["In a limitations question, 'recently' is malpractice — use the date.","State the interval explicitly; the reader shouldn't have to subtract.","Dates are checkable against the record; adverbs aren't."],"focus":["precision","clarity"],"placeholder":"The defect was first noted on March 3; the client complained on April 19 — a 47-day gap."},
    {"id":"precision-law-early-11","level":"early","profession":"lawyer","title":"Data into one insight","scenario":"Your review of the client's 300 customer contracts produced a spreadsheet: 180 auto-renew, 45 have change-of-control clauses, 30 lack limitation-of-liability caps, 12 are governed by foreign law. The partner asked for 'the one thing that matters for the sale.'","task":"Write the single insight the data points to, with the number that anchors it.","tips":["A spreadsheet is data; the partner needs the insight it implies.","The change-of-control clauses are the sale risk — 45 contracts need consents.","One number, one consequence: that's an insight, not a data dump."],"focus":["precision","impact"],"placeholder":"The sale's real friction is consents: 45 of 300 contracts have change-of-control clauses that trigger on the deal."},
    {"id":"precision-law-early-12","level":"early","profession":"lawyer","title":"'Probably fine' with a basis","scenario":"The client asks whether they can use the phrase 'industry-leading' in their marketing without legal risk. You say 'probably fine.' The client deserves the basis: it's puffery, not an actionable claim, as long as they don't attach a specific measurable comparison.","task":"Rewrite as a 2-3 sentence answer that states the rule and the one line that changes it.","tips":["'Probably fine' with no basis is worth nothing to the client.","Give the operative distinction: vague boast (fine) vs. measurable claim (risky).","Draw the bright line they can apply themselves next time."],"focus":["precision","audience"],"placeholder":"'Industry-leading' is fine as a general boast — the line you can't cross is a specific measurable claim like 'rated #1' without proof."},
    {"id":"precision-law-early-13","level":"early","profession":"lawyer","title":"The 'material' that means nothing","scenario":"Your diligence summary says the target has 'several material contracts with some issues.' The partner needs to know which contracts and which issues. You know: two supplier agreements, both with unilateral price-escalation clauses that could raise the target's costs 15%.","task":"Rewrite replacing 'several material contracts with some issues' with the specifics.","tips":["'Material' and 'some issues' are placeholders you forgot to fill in.","Name the contracts, the clause, and the quantified consequence.","'Could raise costs 15%' is what makes 'material' true — show it."],"focus":["precision","impact"]},
    {"id":"precision-law-early-14","level":"early","profession":"lawyer","title":"The estimate with its assumptions","scenario":"The client asks how long the case will take. You say '12 to 18 months.' Good — but the range hides the assumptions that drive it: it assumes no interlocutory appeal and that discovery stays on schedule. Without them, the client can't tell when the number will move.","task":"Write a 2-3 sentence estimate that states the range and the two assumptions it depends on.","tips":["A range without its assumptions can't be updated when facts change.","Name the two swing factors: an appeal, or a discovery blowup.","This lets the client hear later 'the appeal happened' and know why the number moved."],"focus":["precision","clarity"],"placeholder":"Twelve to eighteen months, assuming no interlocutory appeal and that discovery stays on schedule —"},
    {"id":"precision-law-early-15","level":"early","profession":"lawyer","title":"'They breached' — which term?","scenario":"Your demand letter draft says the counterparty 'has breached the agreement in numerous respects.' Opposing counsel will demand specifics. You have them: they missed the June 1 delivery deadline and shipped 200 units short of the order.","task":"Rewrite the accusation naming the exact provisions and the facts that breach them.","tips":["'Numerous respects' invites a demand to specify — specify now.","Cite the section and the fact: Section 4.1's deadline, missed by three weeks.","Precise accusations are harder to deny than sweeping ones."],"focus":["precision","impact"],"placeholder":"You breached Section 4.1 by delivering three weeks after the June 1 deadline, and Section 3.2 by shipping 200 units short —"},
    {"id":"precision-law-early-16","level":"early","profession":"lawyer","title":"The comparison that anchors the fee","scenario":"The client questions the $45,000 discovery cost. Your draft defends it abstractly. A number the client can anchor to: this covered review of 55,000 documents — about 82 cents per document, well below the market rate for outside review.","task":"Write a 2-3 sentence justification built on the per-unit figure and a benchmark.","tips":["A big number needs a denominator to feel fair — cost per document.","Add a benchmark: contract-attorney rates would have cost more.","Precision converts 'expensive' into 'efficient.'"],"focus":["precision","audience"],"placeholder":"The $45,000 covered 55,000 documents — about 82 cents each, below the going rate for outside review."},
    {"id":"precision-law-early-17","level":"early","profession":"lawyer","title":"'The other side seems flexible'","scenario":"You report to the partner that opposing counsel 'seemed flexible on the timeline.' She's about to make strategic decisions on it. What you actually observed: they twice offered to extend deadlines and didn't push back when you raised the confidentiality carve-out.","task":"Rewrite replacing the impression with the specific signals you observed.","tips":["'Seemed flexible' is an inference; the partner wants the observations under it.","Report what they said and did, not your read of their mood.","Let the partner draw the strategic conclusion from the facts."],"focus":["precision","clarity"]},
    {"id":"precision-law-early-18","level":"early","profession":"lawyer","title":"The confidence level, stated","scenario":"Your memo concludes the indemnity claim will succeed but doesn't say how confident you are. The partner is deciding whether to bet a $200K litigation budget on it. Your honest read: better than even, maybe 65%, with the main risk being the notice-timing argument.","task":"Write a 2-sentence conclusion that states your confidence level and the factor that would change it.","tips":["A conclusion without a confidence level forces the partner to guess your certainty.","Give a rough number or 'more likely than not' — and name the swing risk.","Naming the risk that could flip it is what makes the confidence honest."],"focus":["precision","impact"],"placeholder":"I'd put this at better than even — roughly 65% — with the notice-timing argument as the main thing that could flip it."},
    {"id":"precision-law-early-19","level":"early","profession":"lawyer","title":"The vague 'we should update the policy'","scenario":"After reviewing the client's data-retention practices, you write that they 'should update their policy to be more compliant.' The compliance officer needs to know exactly what to change. You found it: they keep customer records seven years when the applicable rule requires deletion after three.","task":"Rewrite as a specific instruction naming the current practice, the rule, and the fix.","tips":["'More compliant' isn't an action — name the gap.","Current state, required state, the change: three concrete facts.","A compliance officer can execute a specific instruction, not a direction."],"focus":["precision","clarity"],"placeholder":"You currently keep customer records seven years; the rule requires deletion after three, so the policy needs a three-year purge —"},
    {"id":"precision-law-early-20","level":"early","profession":"lawyer","title":"The 'various' in the privilege log","scenario":"Your privilege log entry reads 'email re various legal matters.' Opposing counsel will challenge it as inadequate — the log must describe enough to justify the withholding without waiving privilege. The real subject: legal advice on the pending employment claim.","task":"Rewrite the log entry to be specific enough to defend and general enough to protect privilege.","tips":["'Various legal matters' guarantees a challenge — it describes nothing.","Name the subject category and the privilege basis without revealing the advice.","Precision here is protective: a defensible entry avoids in-camera review."],"focus":["precision","clarity"],"placeholder":"Email from counsel providing legal advice regarding the pending employment claim; attorney-client privilege."},
    {"id":"precision-law-early-21","level":"early","profession":"lawyer","title":"The number that changes the recommendation","scenario":"You're advising whether to accept a $90,000 settlement. Your draft weighs the factors qualitatively. The decisive number you buried: expected trial value is about $110,000, but expected additional costs to get there are $60,000 — so settling nets more.","task":"Write a 2-3 sentence recommendation built on the expected-value comparison.","tips":["The recommendation follows from the math — show the math.","Expected trial value minus cost-to-get-there is the honest comparison.","One number ($50K net at trial vs. $90K now) makes the advice self-evident."],"focus":["precision","impact"],"placeholder":"Settle: expected trial value is about $110,000, but reaching it costs roughly $60,000, so the $90,000 offer nets more —"},
    {"id":"precision-law-early-22","level":"early","profession":"lawyer","title":"'Fairly standard terms'","scenario":"You tell the client the proposed contract has 'fairly standard terms.' Standard compared to what? The client is relying on you to spot the exception. There is one: the indemnity is uncapped, which is not standard for a deal this size.","task":"Rewrite the assessment naming what's standard and flagging the one thing that isn't.","tips":["'Standard' is only useful if you also flag the deviation.","Most terms being market gives the client comfort; the uncapped indemnity earns their attention.","The value is in the exception, not the reassurance."],"focus":["precision","impact"],"placeholder":"Most terms are market-standard, with one exception worth flagging: the indemnity is uncapped —"},
    {"id":"precision-law-early-23","level":"early","profession":"lawyer","title":"The 'ASAP' with no anchor","scenario":"You email the paralegal that you need the exhibit binder 'as soon as possible.' She has three other lawyers' ASAPs. The real deadline: the hearing is Thursday at 9am, so you need it by Wednesday noon to review.","task":"Rewrite the request with the exact deadline and the reason behind it.","tips":["'ASAP' competes with every other ASAP — a time wins the queue.","Give the real deadline and the fixed event it derives from.","The reason lets her triage correctly if something has to give."],"focus":["precision","clarity"],"placeholder":"I need the exhibit binder by Wednesday noon — the hearing is Thursday at 9 and I need the afternoon to review."},
    {"id":"precision-law-early-24","level":"early","profession":"lawyer","title":"The evidence for 'they knew'","scenario":"Your brief asserts the defendant 'was aware of the defect.' That's the whole case — and a bare assertion invites the response 'prove it.' You can: an internal email dated two months before the sale flags the exact defect.","task":"Write a 2-sentence passage that pins the knowledge to the specific document and date.","tips":["'Was aware' is a conclusion; the email is the evidence — lead with it.","Date it: knowledge two months pre-sale is what makes it actionable.","Quote or paraphrase the operative line so the reader sees the knowledge, not your claim of it."],"focus":["precision","impact"],"placeholder":"An internal email dated two months before the sale flagged the exact defect: 'the seal fails under load.'"},
    {"id":"precision-law-early-25","level":"early","profession":"lawyer","title":"The client update that passes the skeptic test","scenario":"Your monthly client update says progress is 'good' and things are 'moving along nicely.' The client's GC, a former litigator, reads this as evasion. Every claim should survive her asking 'based on what?' You have the facts: two motions resolved in your favor, discovery 70% done, mediation set for the 15th.","task":"Rewrite the update so every sentence carries a fact a skeptic could verify.","tips":["Imagine the GC writing 'based on what?' next to each sentence — pre-answer it.","Replace 'good' and 'nicely' with the motions, the percentage, the date.","A former litigator trusts specifics and distrusts adjectives."],"focus":["precision","clarity"],"placeholder":"This month: both pending motions resolved in our favor, discovery reached 70% complete, and mediation is confirmed for the 15th."}
  ],
  "executive-presence": [
    {"id":"presence-law-early-01","level":"early","profession":"lawyer","title":"The menu with no recommendation","scenario":"The partner asked what to do about the counterparty's demand. Your memo lays out three options — sue, negotiate, walk away — with pros and cons for each, and stops. She wrote back: 'I can read a pro-con list. What do YOU think we should do?'","task":"Rewrite the closing to state your recommendation and the one reason it beats the others.","tips":["Presenting options without a pick is deferring the judgment they're paying you for.","Recommend one and say why it wins — the pros and cons become your support.","You can still note the runner-up; just don't hide behind neutrality."],"focus":["impact","structure"],"placeholder":"I recommend we negotiate first: it preserves the relationship and costs us nothing to try before suing."},
    {"id":"presence-law-early-02","level":"early","profession":"lawyer","title":"Fact versus your read of it","scenario":"Your update to the partner blends what happened with what you think it means: 'Opposing counsel didn't respond to our offer, which clearly means they're not serious about settling and we should prepare for trial.' The non-response is fact; 'not serious' is your inference presented as fact.","task":"Rewrite separating the observed fact from your judgment, both clearly labeled.","tips":["Facts and inferences carry different weights — don't smuggle one as the other.","'They didn't respond by the deadline' is fact; 'I read this as posturing' is judgment.","Labeling your inference as inference makes it more credible, not less."],"focus":["precision","clarity"],"placeholder":"Fact: they missed the response deadline. My read: this is likely posturing, not a walkaway — here's why."},
    {"id":"presence-law-early-03","level":"early","profession":"lawyer","title":"Owning the recommendation in the room","scenario":"In the case-strategy meeting, the partner turns to you: 'You did the research — what's your call on the summary judgment motion?' Your instinct is to say 'well, it could go either way' and list considerations. You actually have a view: file it, because the facts are undisputed.","task":"Write the 2-3 sentences you'd say to own the call, then support it.","tips":["'It could go either way' abdicates the question you were asked.","Lead with the call — 'I'd file it' — then the reason.","Owning a defensible view builds more trust than hedging a safe one."],"focus":["impact","clarity"],"placeholder":"I'd file it. The core facts are undisputed, so this is exactly the kind of case summary judgment is designed for —"},
    {"id":"presence-law-early-04","level":"early","profession":"lawyer","title":"Signposting the advice email","scenario":"Your advice email to the client covers three things — a decision they need to make, a risk they should know about, and a status update — but they run together in flowing prose. The client keeps replying to only the first thing and missing the decision.","task":"Rewrite with signposts that tell the reader what each part is and what it needs from them.","tips":["Signposts do the reader's navigation: 'Decision needed,' 'For your awareness,' 'Status.'","The label sets the reader's mode before they read the content.","Structure that's visible gets acted on; structure that's implied gets missed."],"focus":["structure","audience"],"placeholder":"Three things below — one needs a decision this week, two are for awareness. DECISION NEEDED:"},
    {"id":"presence-law-early-05","level":"early","profession":"lawyer","title":"The recommendation you're afraid to give","scenario":"The client wants to fire the contractor and sue. Your honest analysis: the contract is weak on their side and suing would cost more than the dispute is worth. You're tempted to present 'considerations' rather than tell a paying client what they don't want to hear.","task":"Write a 2-3 sentence recommendation that gives the unwelcome advice plainly and stands behind it.","tips":["The client hired judgment, including the judgment they didn't want.","State the recommendation, then the number or fact that forces it.","Softening the recommendation into 'considerations' isn't kindness — it's abdication."],"focus":["impact","clarity"],"placeholder":"My honest recommendation is not to sue: the contract favors them, and litigation would cost more than the amount in dispute —"},
    {"id":"presence-law-early-06","level":"early","profession":"lawyer","title":"The apology that undercuts the analysis","scenario":"Your memo is sound, but it's wrapped in self-deprecation: 'I'm not sure this is right, but,' 'I might be missing something, however,' 'this is just my initial take.' The partner has to dig past the apologies to find that your analysis is actually solid.","task":"Rewrite the opening to present the analysis with earned confidence, keeping any genuine caveat.","tips":["Reflexive hedging tells the reader to discount you before you've spoken.","Distinguish real uncertainty (keep, and name it) from nervous habit (cut).","'Here's my analysis' beats 'this is just my initial take' when the work is done."],"focus":["impact","clarity"]},
    {"id":"presence-law-early-07","level":"early","profession":"lawyer","title":"The stand-up answer that wanders","scenario":"At the practice-group stand-up, the partner asks for your status on the Reyes matter. You start narrating everything you did this week. Twelve people are waiting. What they need: it's on track, one blocker, and whether you need anything.","task":"Write the 2-3 sentence status you'd deliver with presence — headline, blocker, ask.","tips":["Presence in a stand-up is respecting the room's time — headline first.","On track / one issue / what you need is the whole update.","End with a clear ask or a clear 'nothing needed' — don't trail off."],"focus":["concision","impact"],"placeholder":"Reyes is on track for the Friday filing. One blocker: I'm waiting on the client's signature — should have it by Wednesday. No help needed."},
    {"id":"presence-law-early-08","level":"early","profession":"lawyer","title":"The judgment call, labeled as such","scenario":"The client asks whether a borderline expense is deductible under the settlement's tax provisions. The law is genuinely unsettled here. Your draft states a firm-sounding answer that overclaims certainty the law doesn't support.","task":"Write a 2-3 sentence answer that gives your best judgment while being honest that it's a judgment.","tips":["Overclaiming certainty on an unsettled question is a presence failure, not a strength.","'My best read is X, and here's the uncertainty' is more authoritative than false confidence.","Presence includes owning the limits of what's knowable."],"focus":["precision","impact"],"placeholder":"My best read is that it's deductible, but I want to be straight that the law here is unsettled — the risk is"},
    {"id":"presence-law-early-09","level":"early","profession":"lawyer","title":"The recommendation with the runner-up acknowledged","scenario":"You're recommending the client accept the settlement, but there's a real case for pushing further, and the client's COO is smart enough to see it. If you pretend the other option doesn't exist, you lose credibility. If you hedge, you lose authority.","task":"Write a 3-4 sentence recommendation that commits to one path while fairly acknowledging the alternative.","tips":["Acknowledging the strong runner-up shows you saw it — that's what earns trust.","Commit clearly, then explain why it beats the alternative you respect.","'I considered pushing and here's why I'd still settle' is the mark of judgment."],"focus":["impact","structure"],"placeholder":"I recommend accepting. Pushing further is defensible — the offer is below your best-case — but the added cost and delay outweigh the likely gain because"},
    {"id":"presence-law-early-10","level":"early","profession":"lawyer","title":"The email that leads with process, not point","scenario":"You email the partner: 'I reviewed the file, then researched the statute, then checked the case law, and after considering everything, I think we should oppose the motion.' The recommendation — oppose — is buried behind your process narration.","task":"Rewrite so the recommendation leads and the process, if kept at all, is one clause.","tips":["Nobody grades your process; they act on your conclusion — lead with it.","'We should oppose the motion' is the sentence; the research is how you know.","Process narration reads as junior; the conclusion reads as counsel."],"focus":["impact","concision"],"placeholder":"We should oppose the motion. The statute and the case law both cut our way —"},
    {"id":"presence-law-early-11","level":"early","profession":"lawyer","title":"Disagreeing with the partner, with presence","scenario":"The partner wants to file a motion you think is a mistake — the facts don't support it and losing would signal weakness. You're junior, but you're closest to the record. Staying silent isn't loyalty; it's a failure of your job.","task":"Write a 3-4 sentence message that raises the disagreement respectfully but clearly, with your reasoning.","tips":["Presence isn't only agreeing well — it's dissenting without either caving or fighting.","Lead with respect for the call, then your specific concern and evidence.","Offer an alternative, so you're contributing a solution, not just an objection."],"focus":["impact","clarity"],"placeholder":"Before we file, I want to flag a concern — the record may not support the motion, and here's what I'm seeing:"},
    {"id":"presence-law-early-12","level":"early","profession":"lawyer","title":"The 'I think maybe possibly' answer","scenario":"The client asks a direct question on the call: can they terminate the lease early? You know the answer is yes with a penalty. But you hear yourself say 'I think it's possible you might be able to, potentially, depending.' The client's confidence in you drops in real time.","task":"Write the 2-sentence spoken answer you'd give with the hedges removed.","tips":["Direct questions with clear answers deserve clear answers.","'Yes, with a penalty' is the answer; the depending-on is one named condition, not a fog.","Stacked qualifiers on a known answer read as insecurity, not care."],"focus":["impact","concision"],"placeholder":"Yes, you can terminate early — there's a penalty of two months' rent, but the right is clearly there."},
    {"id":"presence-law-early-13","level":"early","profession":"lawyer","title":"Owning a mistake without collapsing","scenario":"You missed a minor filing formatting requirement and the clerk bounced the document. It's fixable same-day. Your draft to the partner over-apologizes across a paragraph, which makes a small problem look like a crisis and you look shaken.","task":"Write a 2-3 sentence message that owns the error, states the fix, and moves on with composure.","tips":["Presence under a mistake is calm ownership, not groveling.","Name it, name the fix, name the timeline — then stop.","Over-apologizing inflates the error and drains your credibility."],"focus":["impact","clarity"],"placeholder":"The clerk bounced the filing on a formatting rule — my miss. Corrected and refiling this afternoon; no deadline impact."},
    {"id":"presence-law-early-14","level":"early","profession":"lawyer","title":"The recommendation to a skeptical client","scenario":"The client's CFO thinks lawyers always recommend the expensive, cautious path. You're about to recommend they add a costly indemnity provision. To land it, you need to own the recommendation while showing you weighed the cost he's worried about.","task":"Write a 3-4 sentence recommendation that commits and pre-answers the 'you're just being cautious' objection.","tips":["Owning a recommendation includes showing you priced the downside they fear.","Name the cost, then show why the risk it covers is worth more.","Presence with a skeptic is confidence plus visible cost-awareness."],"focus":["impact","audience"],"placeholder":"I'm recommending the indemnity even though it isn't free — here's the specific exposure it covers and why I think it's worth the cost:"},
    {"id":"presence-law-early-15","level":"early","profession":"lawyer","title":"The signposted memo opening","scenario":"Your ten-page memo has good structure internally, but the opening drops the reader straight into analysis with no map. The partner reads better when she knows up front: here's the answer, here are the three issues, here's where the risk is.","task":"Write a 3-4 sentence opening that states the bottom line and signposts what follows.","tips":["A signposted opening earns the reader's patience for the pages after.","Bottom line, then 'this turns on three issues,' then where the risk sits.","The map is presence — it says you're in control of the material."],"focus":["structure","impact"],"placeholder":"Bottom line: the client can enforce the clause, with one fixable weakness. This turns on three issues —"},
    {"id":"presence-law-early-16","level":"early","profession":"lawyer","title":"The neutral summary that dodges","scenario":"The partner asked which of two experts to retain. You wrote a balanced summary of both CVs and left the choice to her. But you've spoken to both and have a clear preference — the second is sharper on cross. Handing back a neutral summary wastes your access.","task":"Write a 2-3 sentence recommendation that names your pick and the differentiator.","tips":["A neutral summary of things you have a view on is a missed contribution.","You did the interviews — your read is the value, not the CVs.","Name the pick and the single reason that tips it."],"focus":["impact","precision"],"placeholder":"I'd retain Dr. Okafor. Both are qualified, but she was noticeably sharper under my mock cross —"},
    {"id":"presence-law-early-17","level":"early","profession":"lawyer","title":"The fact-judgment blur in a risk flag","scenario":"You flag to the partner: 'The contract's arbitration clause is unenforceable and we'll win any challenge.' The first part is arguable law; the second is a prediction. Presenting both as certainties overclaims and could mislead a decision.","task":"Rewrite separating the legal fact, your assessment of it, and the prediction — each at its true confidence.","tips":["Three different claims are hiding as one certainty — pull them apart.","'The clause is arguably unenforceable / I'd give us 70% / a challenge is worth trying' calibrates each layer.","Blurring fact and prediction is how confident-sounding advice becomes wrong advice."],"focus":["precision","impact"]},
    {"id":"presence-law-early-18","level":"early","profession":"lawyer","title":"The stretch assignment ask, owned","scenario":"You want to argue a discovery motion in court — a stretch for someone at your level, but you're ready. Your draft to the partner is so tentative ('if you think I'm ready, and only if it's not too important') that it invites a no.","task":"Write a 2-3 sentence request that states the ask with confidence and gives the partner a reason to say yes.","tips":["Asking for a stretch with presence means owning that you're ready, not begging.","State the specific ask and the preparation that backs it.","Give the partner the low-risk framing — you'll be fully prepped, she can review."],"focus":["impact","audience"],"placeholder":"I'd like to argue the motion to compel next week. I've done the research and I'm ready to prep fully for your review —"},
    {"id":"presence-law-early-19","level":"early","profession":"lawyer","title":"The recommendation buried in a data table","scenario":"You built a comparison table of three settlement structures with columns for tax treatment, timing, and net recovery. It's thorough. But you leave the partner to read it and decide, when your analysis clearly favors the third structure.","task":"Write the 2-3 sentence lead-in to the table that states your recommendation and points to the winning row.","tips":["A table informs; it doesn't decide — decide, then let the table support you.","Name the pick and the column that drives it: highest net recovery after tax.","The reader should know your answer before they read the table, not after."],"focus":["impact","structure"],"placeholder":"I recommend Structure 3 — it delivers the highest net recovery after tax, as the table shows. The tradeoff is timing:"},
    {"id":"presence-law-early-20","level":"early","profession":"lawyer","title":"The 'whatever you think' close","scenario":"You end your advice email with 'but of course it's your call, whatever you think is best.' It's meant as deference to the client, but it evaporates the recommendation you just spent three paragraphs building, and leaves them exactly where they started.","task":"Rewrite the closing so it respects the client's decision authority without dissolving your advice.","tips":["Deference and a clear recommendation coexist — 'it's your call, and my advice is X.'","'Whatever you think' hands back the judgment you were paid to provide.","Close on the recommendation, then acknowledge it's theirs to accept."],"focus":["impact","audience"],"placeholder":"The decision is yours, and my recommendation is clear: accept the offer. If you'd like to talk it through before deciding, I'm free tomorrow."},
    {"id":"presence-law-early-21","level":"early","profession":"lawyer","title":"Presence when you don't have the answer yet","scenario":"On the client call, the CEO asks a question you haven't researched: does the new regulation apply retroactively? Blustering a guess would be worse than not knowing. But 'I don't know' with nothing else sounds unprepared.","task":"Write the 2-sentence spoken response that maintains presence while being honest you'll confirm.","tips":["Presence isn't knowing everything — it's handling the gap with control.","'I don't want to guess on retroactivity — I'll confirm by tomorrow' beats a wrong guess.","Attach a concrete when, so the honesty reads as competence, not evasion."],"focus":["impact","clarity"],"placeholder":"I don't want to give you a half-answer on retroactivity — it's a specific point I'll confirm and get back to you by tomorrow morning."},
    {"id":"presence-law-early-22","level":"early","profession":"lawyer","title":"The judgment the partner didn't ask for but needs","scenario":"The partner asked you to summarize the deposition. Reading it, you spotted a strategic problem she didn't ask about: the client's own testimony contradicts the complaint. A summary that omits your judgment on this would be technically responsive and practically useless.","task":"Write a 2-3 sentence note that delivers the summary but leads with the judgment she needs.","tips":["Presence includes surfacing the thing they'd want to know but didn't ask.","Lead with the strategic problem, then the summary as support.","Volunteering relevant judgment is what separates counsel from a transcriber."],"focus":["impact","structure"],"placeholder":"Summary attached, but one thing needs your attention first: the client's testimony contradicts a key allegation in our complaint —"},
    {"id":"presence-law-early-23","level":"early","profession":"lawyer","title":"The recommendation under time pressure","scenario":"The partner calls: opposing counsel wants an answer on the extension in ten minutes, and she wants your recommendation now. You're tempted to list considerations. She needs a decision she can act on immediately.","task":"Write the 2-sentence spoken recommendation you'd give — a clear call with one reason.","tips":["Under time pressure, a clear call with one reason beats a complete analysis.","'Grant it, because refusing buys us nothing and costs goodwill' is actionable now.","Presence under pressure is decisiveness, not exhaustiveness."],"focus":["impact","concision"],"placeholder":"Grant the extension. Refusing gains us nothing and burns goodwill we'll want later —"},
    {"id":"presence-law-early-24","level":"early","profession":"lawyer","title":"The confident close on a client memo","scenario":"Your client memo is strong through the analysis but ends limply: 'I hope this is helpful, let me know if you have any questions or if you'd like me to look into anything else.' The ending drains the authority the memo built.","task":"Rewrite the closing to end on the recommendation and a clear next step.","tips":["A limp close undoes a strong memo — end on substance, not a service formula.","Restate the bottom line and name the next action.","'Here's what I'd do next, and I'll have it ready by Friday' closes with presence."],"focus":["impact","clarity"],"placeholder":"My recommendation stands: renegotiate the indemnity before signing. I'll have the proposed language to you by Friday."},
    {"id":"presence-law-early-25","level":"early","profession":"lawyer","title":"Separating what happened from what it means","scenario":"You're briefing the partner after a settlement conference. Your draft mixes the reporter's facts with your strategic read: 'The mediator was pessimistic, which means we're in a weak position and should lower our number.' The mediator's tone is data; 'weak position' is your interpretation.","task":"Rewrite so the partner can see the facts and your interpretation as distinct, each usable on its own.","tips":["The partner may agree with your facts but disagree with your read — let her.","Report the mediator's actual signals, then label your strategic conclusion separately.","Fused, your interpretation contaminates the facts; separated, both are trustworthy."],"focus":["precision","clarity"],"placeholder":"What happened: the mediator pushed hard on our damages theory and floated a lower range. My read: this is pressure, not a verdict — I wouldn't move our number yet because"}
  ],
  "answering-under-pressure": [
    {"id":"pressure-law-early-01","level":"early","profession":"lawyer","title":"Answer the question, then explain","scenario":"The client's CEO asks flatly on the call: 'Are we going to win?' You start explaining the litigation process and the factors involved. He interrupts: 'I asked if we're going to win.' You have a real answer — more likely than not, with one wildcard.","task":"Write the 2-3 sentence answer that responds to his actual question first, then adds the nuance.","tips":["Under pressure, the instinct is to explain around the question — resist it.","Give the direct answer first: 'More likely than not.' Then the caveat.","Answering first earns you the right to add the nuance the answer needs."],"focus":["clarity","impact"],"placeholder":"More likely than not, yes — I'd put us ahead. The one wildcard is the credibility fight over the key witness —"},
    {"id":"pressure-law-early-02","level":"early","profession":"lawyer","title":"The partner's pushback on your research","scenario":"You recommended not filing a motion. The partner pushes back hard: 'That's too cautious — why wouldn't we file?' Your instinct is to fold. But your reason is solid: the controlling case in this circuit went the other way on identical facts.","task":"Write a 2-3 sentence response that holds your position with the specific fact, not defensiveness.","tips":["Pushback tests whether your reason is real — meet it with the fact, not an apology.","'The controlling case in this circuit cuts against us on the same facts' answers the challenge.","Don't cave and don't fight — cite the evidence that drove the recommendation."],"focus":["precision","clarity"],"placeholder":"I'd hold there — not out of caution, but because the controlling case here went the other way on nearly identical facts:"},
    {"id":"pressure-law-early-03","level":"early","profession":"lawyer","title":"The 'I don't know' with a path","scenario":"In a client meeting, the general counsel asks whether a specific state's law recognizes a particular defense. You genuinely don't know off the top of your head, and guessing on the record is dangerous. Silence or bluffing both fail.","task":"Write the 2-sentence response that admits the gap honestly and gives a concrete path to the answer.","tips":["'I don't know' is a complete, professional answer when paired with a plan.","Name when and how you'll close the gap — 'I'll confirm by end of day.'","Bluffing a legal answer you're unsure of is the actual failure, not admitting the gap."],"focus":["clarity","impact"],"placeholder":"I don't want to guess on that state's rule — it varies more than you'd expect. I'll confirm it and have a clear answer to you by this afternoon."},
    {"id":"pressure-law-early-04","level":"early","profession":"lawyer","title":"The client who wants a guarantee","scenario":"The client presses: 'Just tell me we'll win, or I'll find a lawyer who will.' You can't ethically or honestly guarantee an outcome. Caving to the pressure would be a lie; a lecture on uncertainty would lose him.","task":"Write a 3-4 sentence response that holds the line honestly while keeping the client's confidence.","tips":["Pressure to guarantee is pressure to lie — meet it with honest confidence, not a promise.","Reframe: 'No honest lawyer guarantees outcomes, but here's why I like our position.'","Give him the specific reasons for confidence — that's what he actually wants."],"focus":["clarity","impact"],"placeholder":"I won't promise you a win — no honest lawyer can, and you'd be right to distrust one who did. What I can tell you is why I like our odds:"},
    {"id":"pressure-law-early-05","level":"early","profession":"lawyer","title":"Deflecting the loaded question, straight","scenario":"On a call, opposing counsel asks you point-blank: 'Is your client willing to go above $500K?' Answering yes or no both cost you leverage, but dodging clumsily signals weakness. You need a composed non-answer that keeps the pressure off.","task":"Write the 1-2 sentence response that neither concedes nor evades awkwardly.","tips":["A composed 'I'm not going to negotiate against myself' is stronger than a dodge.","Redirect to their side's move without conceding your range.","Under pressure, calm brevity reads as control; over-talking reads as leaking."],"focus":["clarity","concision"],"placeholder":"I'm not going to negotiate against my own client — if your client has a number in mind, I'll take it to mine."},
    {"id":"pressure-law-early-06","level":"early","profession":"lawyer","title":"When the partner catches an error live","scenario":"In the meeting, the partner points out you cited a case that was overruled. You did miss it. The room is watching. Panicking or over-explaining both make it worse; so does pretending it doesn't matter.","task":"Write the 2-sentence response that acknowledges the error cleanly and states the fix.","tips":["Own it in one sentence — no defensiveness, no spiral.","State what it changes and how you'll fix it: 'I'll find current authority today.'","Composure under a caught error is more memorable than the error."],"focus":["clarity","impact"],"placeholder":"You're right — that case was overruled and I missed it. I'll find current authority for the point and confirm the argument still holds by this afternoon."},
    {"id":"pressure-law-early-07","level":"early","profession":"lawyer","title":"The interrogating client on fees","scenario":"The client's controller demands, sharply: 'Why did this month cost $30,000 more than last month?' There's a real answer — the deposition prep and the emergency injunction response — but your instinct under the sharp tone is to get defensive.","task":"Write a 2-3 sentence response that answers the actual question with specifics, not defense.","tips":["A sharp question deserves a factual answer, not an emotional one.","Name the two drivers that account for the delta — depositions and the injunction.","Specifics defuse suspicion; defensiveness confirms it."],"focus":["clarity","precision"],"placeholder":"Two things drove it: three days of deposition prep and the emergency injunction response the court forced on a short fuse —"},
    {"id":"pressure-law-early-08","level":"early","profession":"lawyer","title":"The question inside the question","scenario":"The client asks: 'How much longer is discovery going to take?' But the real worry underneath is money — every month of discovery is another invoice. Answering only the literal timeline misses what he's actually asking.","task":"Write a 2-3 sentence response that answers the timeline and addresses the cost concern behind it.","tips":["Under pressure, hear the question behind the question — here it's cost, not calendar.","Give the timeline, then pre-empt the money worry with the cost trajectory.","Answering the real concern builds trust the literal answer wouldn't."],"focus":["clarity","audience"],"placeholder":"About six more weeks — and since I suspect the real question is cost, that's roughly $X more, after which the spend drops sharply."},
    {"id":"pressure-law-early-09","level":"early","profession":"lawyer","title":"Holding under the 'that's ridiculous'","scenario":"You advise the client that the opposing party's claim, while weak, can't simply be ignored. The founder erupts: 'That's ridiculous, the claim is garbage, why are we even discussing it?' He's not wrong that it's weak — but ignoring it has real consequences.","task":"Write a 3-4 sentence response that validates his instinct, holds your point, and explains the stakes.","tips":["Meet the heat by agreeing where he's right — the claim is weak.","Then hold the point that matters: weak claims still require a response or they win by default.","Give the concrete consequence of ignoring it, so 'why discuss it' answers itself."],"focus":["clarity","impact"],"placeholder":"You're right that the claim is weak — but here's why we still have to engage it: an unanswered claim, even a bad one, can result in a default judgment against you."},
    {"id":"pressure-law-early-10","level":"early","profession":"lawyer","title":"The rapid-fire deposition-prep questions","scenario":"You're prepping the client's employee for her deposition and she fires anxious questions: 'What if I don't remember? What if they trick me? What if I say the wrong thing?' Answering each in a long paragraph will overwhelm her more.","task":"Write short, direct answers to all three fears in 3-4 sentences total.","tips":["Anxious rapid-fire questions need short, steady answers, not essays.","'I don't remember' is a fine answer — say that plainly.","Calm brevity is itself reassuring; over-explaining amplifies the fear."],"focus":["clarity","concision"],"placeholder":"If you don't remember, you say 'I don't remember' — that's a complete, honest answer. There are no tricks that beat telling the truth simply, and"},
    {"id":"pressure-law-early-11","level":"early","profession":"lawyer","title":"The senior associate's skeptical 'are you sure?'","scenario":"You tell the senior associate the deadline is Friday. She asks, with an edge, 'Are you sure? Double-check that.' You did check — you're sure — but the doubt makes you want to hedge into 'I think so.'","task":"Write the 1-2 sentence response that confirms with the source, not a nervous walk-back.","tips":["'Are you sure' tests confidence — confirm with how you know, don't retreat.","'Yes — the scheduling order sets it at Friday the 14th, I checked the docket' ends it.","Citing your basis is stronger than either 'yes' alone or 'well, I think.'"],"focus":["clarity","precision"],"placeholder":"Yes — Friday the 14th, per the scheduling order on the docket. I confirmed it against the order itself, not just my calendar."},
    {"id":"pressure-law-early-12","level":"early","profession":"lawyer","title":"The client's 'why didn't you catch this?'","scenario":"A problem surfaced in the contract — a renewal auto-triggered because nobody flagged the notice window. The client demands: 'Why didn't you catch this?' The honest answer is that the renewal tracking wasn't in your engagement scope, but saying that defensively sounds like blame-shifting.","task":"Write a 3-4 sentence response that addresses accountability honestly without either falsely accepting blame or deflecting coldly.","tips":["Under an accusatory question, be honest about scope without weaponizing it.","Acknowledge the client's frustration and the real gap before explaining scope.","Pivot fast to the fix — what to do now matters more than whose fault."],"focus":["clarity","impact"]},
    {"id":"pressure-law-early-13","level":"early","profession":"lawyer","title":"The hostile question at the client's board","scenario":"You're presenting to the client's board and a director challenges: 'You've spent six months and a lot of money — what do we actually have to show for it?' It stings, but it's a fair question with a real answer: two dismissed claims and a favorable evidentiary ruling.","task":"Write a 3-4 sentence response that answers the challenge with concrete results, composed.","tips":["A hostile board question is answered with results, not with hurt.","Lead with the wins that money bought: claims dismissed, ruling secured.","Composure plus specifics turns a challenge into a credibility moment."],"focus":["clarity","precision"],"placeholder":"Fair question. In six months we've gotten two of the four claims dismissed and won a key evidentiary ruling that shapes the rest of the case —"},
    {"id":"pressure-law-early-14","level":"early","profession":"lawyer","title":"The 'just give me a yes or no'","scenario":"The client's COO cuts you off: 'I don't need the whole analysis — can we terminate the contract, yes or no?' The true answer is 'yes, but only for cause, and proving cause is the hard part.' A bare yes misleads; a bare no is wrong.","task":"Write a 2-3 sentence response that gives the yes-or-no he wants while flagging the one thing he must know.","tips":["Respect the demand for a direct answer — but don't let 'yes' mislead.","'Yes, but only for cause — and cause is the part we'd have to prove' honors both.","The one caveat that changes his decision earns its place; the rest doesn't."],"focus":["clarity","concision"],"placeholder":"Yes — but only for cause, not at will. The catch is that we'd have to prove the cause, and that's the real work."},
    {"id":"pressure-law-early-15","level":"early","profession":"lawyer","title":"When you're asked something outside your matter","scenario":"On the client call about litigation, the CEO suddenly asks a tax question about the settlement structure — outside your expertise and your matter. Faking competence risks giving wrong advice; a flat 'not my area' feels like a brush-off.","task":"Write a 2-sentence response that honestly declines to opine but keeps the client served.","tips":["Answering outside your competence under pressure is how bad advice happens.","'That's a tax question I don't want to wing — let me connect you with our tax group' serves them better.","Declining plus a handoff is service, not a dodge."],"focus":["clarity","impact"],"placeholder":"That's really a tax question, and I don't want to give you a half-right answer on it — let me loop in our tax group so you get it right."},
    {"id":"pressure-law-early-16","level":"early","profession":"lawyer","title":"The partner's 'convince me' on strategy","scenario":"You've proposed settling. The partner leans back: 'Convince me. Why shouldn't we take this to trial and win big?' It's a test, not hostility. You have the answer: the upside is real but the cost and 40% loss risk make the expected value worse than the offer.","task":"Write a 3-4 sentence response that makes the affirmative case under the challenge.","tips":["'Convince me' invites your best argument — deliver it, don't shrink from it.","Acknowledge the trial upside is real, then show why the math still favors settling.","Under 'convince me,' confidence with numbers wins; hedging loses."],"focus":["clarity","impact"],"placeholder":"Trial upside is real — but here's the math: a 40% chance of losing plus $200K in costs makes the expected value of trial lower than the offer on the table."},
    {"id":"pressure-law-early-17","level":"early","profession":"lawyer","title":"The client who won't accept the answer","scenario":"You've told the client three times that the non-disclosure obligation survives termination — it's clear in the contract. He keeps re-asking, hoping for a different answer. Repeating the same words louder won't help.","task":"Write a 2-3 sentence response that closes the loop firmly and reframes so he can accept it.","tips":["Re-asking is often not-accepting — address the resistance, not just the fact.","Anchor to the contract language so it's the document saying no, not you.","Offer a forward path — what he can do about it — so 'no' isn't a dead end."],"focus":["clarity","impact"],"placeholder":"I know this isn't the answer you want, but the contract is explicit: Section 9 says the NDA survives termination. What we can do instead is"},
    {"id":"pressure-law-early-18","level":"early","profession":"lawyer","title":"The gotcha on inconsistent advice","scenario":"The client's manager challenges: 'Last month you said we could do this, now you're saying we can't — which is it?' There's a real explanation: the facts changed when the counterparty added a new term. But it reads as flip-flopping unless you handle it precisely.","task":"Write a 3-4 sentence response that explains the change of position with the changed fact, not defensiveness.","tips":["An apparent contradiction under pressure needs the fact that reconciles it.","Name what changed: 'The advice changed because the contract changed.'","Own the confusion, then make the distinction crisp so it doesn't recur."],"focus":["clarity","precision"]},
    {"id":"pressure-law-early-19","level":"early","profession":"lawyer","title":"The urgent 'what do we do RIGHT NOW'","scenario":"The client calls in a panic — they just received a cease-and-desist and a deadline of noon tomorrow. 'What do we do right now?' Launching into legal analysis is the wrong move; they need immediate, concrete direction and a lowered temperature.","task":"Write a 3-4 sentence response that gives the one immediate action and calms the crisis.","tips":["In a genuine urgency, lead with the single next action, not the analysis.","'First, don't respond to them directly — forward it to me and do nothing else today' is actionable.","Calm is contagious; give the one step and the timeline for the rest."],"focus":["clarity","impact"],"placeholder":"First thing: don't respond to them yourself — forward it to me and do nothing else today. The noon deadline is real but manageable, and here's what happens next:"},
    {"id":"pressure-law-early-20","level":"early","profession":"lawyer","title":"The question you half-know","scenario":"The partner asks whether the client's insurance policy covers this type of claim. You've skimmed the policy and think yes, but you're only 70% sure and haven't checked the exclusions. Claiming full certainty risks being wrong; claiming full ignorance wastes what you do know.","task":"Write a 2-sentence response that gives your partial knowledge honestly with its confidence level and the gap.","tips":["Partial knowledge is useful if you label the part you're unsure of.","'Likely yes on the main coverage, but I haven't cleared the exclusions' is precise honesty.","State the specific thing you still need to check, not a vague 'I'll look into it.'"],"focus":["clarity","precision"],"placeholder":"My read so far is that the main coverage grant applies — but I haven't worked through the exclusions yet, which is where these often turn, so let me confirm before you rely on it."},
    {"id":"pressure-law-early-21","level":"early","profession":"lawyer","title":"The pointed 'did you actually read it?'","scenario":"The partner, frustrated by a gap in your memo, asks: 'Did you actually read the whole contract?' You did — the gap was a judgment call about relevance, not a miss. But the question invites either a wounded defense or a false confession.","task":"Write a 2-3 sentence response that answers the real concern with what you did and why, calmly.","tips":["Answer the substance behind the sting, not the sting.","Confirm you read it, then explain the judgment: 'I read it and left out Section 12 because I judged it immaterial — I may have called that wrong.'","Openness to being wrong on the judgment reads better than defending it to the death."],"focus":["clarity","impact"]},
    {"id":"pressure-law-early-22","level":"early","profession":"lawyer","title":"The client testing your loyalty","scenario":"The client asks you to take a position you think is a stretch: 'Can't you just argue the contract means what we want it to mean?' There's pressure to please. But an argument you can't defend will hurt them and you. You need to say no without sounding disloyal.","task":"Write a 3-4 sentence response that declines the weak argument while affirming you're on their side.","tips":["Loyalty is protecting the client's interest, not their preferred reading.","Explain that a losing argument costs credibility for the winning ones.","Offer the strongest honest argument as the constructive alternative."],"focus":["clarity","impact"],"placeholder":"I'm on your side, which is exactly why I won't run that argument — a judge will see through it and it'll cost us credibility on the points we can win. Here's the strongest honest version:"},
    {"id":"pressure-law-early-23","level":"early","profession":"lawyer","title":"The surprise question in the client meeting","scenario":"Mid-meeting, the client's VP springs a question you weren't prepped for: 'What's our exposure if this leaks to the press?' You have thoughts but no analysis. Winging a number would be reckless; freezing loses the room.","task":"Write a 2-3 sentence response that engages the question substantively while being clear you'll follow up rigorously.","tips":["Engage the shape of the question even when you lack the numbers.","Name the two or three factors that would drive the answer — that shows command.","Commit to the rigorous follow-up so the interim answer isn't mistaken for the final one."],"focus":["clarity","structure"],"placeholder":"Good question, and I'd want to give you a real answer rather than a guess. Off the top, the exposure turns on two things — the confidentiality obligations and any regulatory disclosure duty — and I'll have a proper read by"},
    {"id":"pressure-law-early-24","level":"early","profession":"lawyer","title":"The 'stop hedging and tell me'","scenario":"The client, exasperated, says: 'Every answer you give me has an if and a but. Just tell me what you'd do.' Some of your hedges are real uncertainty; some are habit. He's asking you to commit to a recommendation.","task":"Write a 2-3 sentence response that commits to a clear recommendation and keeps only the caveat that's genuinely load-bearing.","tips":["When asked to commit, separate the real caveat from the reflexive one.","State what you'd do in a plain sentence — earn the trust the directness buys.","Keep the one 'but' that would actually change the decision, and drop the rest."],"focus":["clarity","concision"],"placeholder":"Fair — here's what I'd do: accept the offer and close it this week. The only real 'but' worth keeping is"},
    {"id":"pressure-law-early-25","level":"early","profession":"lawyer","title":"When the answer is genuinely bad news under a hopeful question","scenario":"The client asks, hopefully, 'So we can still enforce the warranty, right?' The honest answer is no — the notice deadline passed and the claim is gone. The hopeful framing tempts you to soften it into ambiguity. That would be worse.","task":"Write a 2-3 sentence response that answers the hopeful question honestly and immediately pivots to what remains possible.","tips":["A hopeful question deserves an honest answer, not a comforting fog.","Give the bad news cleanly, then move to the still-open path so it isn't all loss.","Under the pressure to please, clarity is the greater kindness."],"focus":["clarity","impact"],"placeholder":"I wish I had a yes, but I don't — the warranty claim is barred because the notice deadline passed. Here's what's still open to us, though:"}
  ],
  "narrative-and-persuasion": [
    {"id":"narrative-law-early-01","level":"early","profession":"lawyer","title":"The demand letter that tells a story","scenario":"You're drafting a demand letter over an unpaid invoice. Your instinct is to lead with the legal claim and contract sections. But the letter persuades more if it tells the story first: the client delivered exactly what was promised, on time, and the other side simply hasn't paid.","task":"Write a 3-4 sentence opening that frames the before-and-after: the deal made, the promise kept, the breach that followed.","tips":["Persuasion starts with a story the reader recognizes as fair, then names the wrong.","Frame the change: everything went right until they didn't pay.","The legal citations land harder after the narrative makes the reader want them to."],"focus":["impact","structure"],"placeholder":"Our client did everything the contract required — delivered the full order by the June deadline, to spec. Your client accepted it, used it, and then simply stopped paying."},
    {"id":"narrative-law-early-02","level":"early","profession":"lawyer","title":"Make the stakes concrete for the client","scenario":"You're recommending the client settle rather than fight. Abstractly, they hear 'litigation is risky.' To persuade, you need to make the stakes concrete: two years of their CEO's time in depositions, their financials made public in discovery, and a 40% chance of a worse outcome than the offer.","task":"Write a 3-4 sentence passage that makes the cost of fighting vivid and specific.","tips":["'Risky' is abstract; two years and public financials are concrete stakes.","Translate risk into things the client can feel — time, exposure, distraction.","Concrete stakes persuade; abstract warnings get discounted."],"focus":["impact","precision"],"placeholder":"Fighting this means two years where your CEO gives depositions instead of running the company, your financials become public record, and even then there's a real chance"},
    {"id":"narrative-law-early-03","level":"early","profession":"lawyer","title":"Pre-empt the strongest counterargument","scenario":"Your brief argues the contract was breached. The other side's best response is that your client waived the breach by continuing to accept deliveries. If you ignore it, the judge hears it fresh from opposing counsel. If you address it first, you control the framing.","task":"Write a 3-4 sentence passage that raises the waiver argument and defuses it before the other side can.","tips":["Pre-empting the best objection shows the judge you're not hiding from it.","State their argument fairly, then dismantle it — a strawman fools no one.","Owning the counterargument makes your whole brief more credible."],"focus":["impact","structure"],"placeholder":"The other side will argue our client waived the breach by continuing to accept deliveries. That argument fails because"},
    {"id":"narrative-law-early-04","level":"early","profession":"lawyer","title":"The persuasive case summary for the partner","scenario":"You want the partner to take a contingency case you believe in. A dry recitation of the claims won't move her. You need to tell it as a story: a small supplier, a big customer who changed the deal after the work was done, and clean documents proving it.","task":"Write a 3-4 sentence pitch that frames the case as a compelling, winnable story.","tips":["A case pitch is a story with a sympathetic client and a clear villain move.","Lead with the human frame, then the evidence that makes it winnable.","The partner funds stories she can see herself telling a jury."],"focus":["impact","structure"],"placeholder":"This is a clean one: a small supplier did the work, the big customer moved the goalposts after delivery, and we have the emails proving they knew —"},
    {"id":"narrative-law-early-05","level":"early","profession":"lawyer","title":"The 'why now' for the client's decision","scenario":"You're urging the client to sign the settlement this week, but they want to 'think about it.' The persuasion isn't in more analysis — it's in framing why the moment matters: the offer expires Friday, and after that trial costs start accruing that make the same deal net worse.","task":"Write a 2-3 sentence passage that creates honest urgency around the decision.","tips":["Persuasion often turns on 'why now,' not just 'why.'","Make the cost of waiting concrete: the offer expires, then costs eat the value.","Honest urgency is a real deadline, not manufactured pressure."],"focus":["impact","precision"],"placeholder":"The reason to decide this week isn't pressure — it's math: the offer expires Friday, and once trial prep restarts, the same deal nets you less because"},
    {"id":"narrative-law-early-06","level":"early","profession":"lawyer","title":"Framing the contract change as a win","scenario":"You negotiated a change that benefits the client, but it came with a small concession. When you report it, you can frame it as a loss ('we had to give up X') or as the win it is ('we got the liability cap we needed, at the cost of a minor reporting requirement').","task":"Write a 2-3 sentence report that frames the outcome accurately as the net win it is.","tips":["Framing isn't spin if it's honest — lead with what was gained, name the cost fairly.","The reader takes their cue from your framing; give them the accurate one.","'We won X for a minor Y' is truthful and persuasive; 'we had to give up Y' isn't the whole truth."],"focus":["impact","audience"],"placeholder":"Good result: we got the liability cap you wanted. The only trade was a quarterly reporting line, which costs you almost nothing —"},
    {"id":"narrative-law-early-07","level":"early","profession":"lawyer","title":"The before-and-after in the settlement pitch to the other side","scenario":"You're writing to opposing counsel to propose settlement. To persuade their client to accept, you need to paint two futures: settle now for a known, contained number, or litigate into an expensive, public, uncertain fight. The contrast does the persuading.","task":"Write a 3-4 sentence passage contrasting the settle path with the litigate path, to their client's own interest.","tips":["Persuade the other side by showing the deal is in their interest, not just yours.","Contrast the two futures concretely — certain and contained vs. costly and public.","A settlement letter that only threatens invites a fight; one that shows a better path invites a deal."],"focus":["impact","structure"],"placeholder":"Your client faces a choice between a contained resolution now and an open-ended fight. Settling closes this quietly for a known number; litigating means"},
    {"id":"narrative-law-early-08","level":"early","profession":"lawyer","title":"Making the risk memo land","scenario":"Your risk memo warns the client against a course of action, but it reads as a dry list of legal risks that they'll skim and ignore. To persuade, you need one concrete scenario that shows the risk playing out — a story, not a list.","task":"Write a 3-4 sentence passage that dramatizes the top risk as a plausible sequence of events.","tips":["A list of risks gets skimmed; one vivid scenario gets remembered.","Walk the reader through how the risk actually unfolds, step by step.","Make them see the bad outcome, then they'll act to avoid it."],"focus":["impact","structure"],"placeholder":"Picture how this plays out: you terminate without the notice, the distributor sues, and because the contract required 90 days, a court reinstates them — now you're stuck with the partner you wanted gone, plus their legal fees."},
    {"id":"narrative-law-early-09","level":"early","profession":"lawyer","title":"The client testimonial you need them to give","scenario":"You need the client's operations lead to write a declaration supporting the motion, but he sees it as a chore. To persuade him to engage, you have to connect the declaration to what he cares about — this is his chance to put the true version of events on the record.","task":"Write a 2-3 sentence message that frames the declaration as serving his interest, not just yours.","tips":["Persuade by connecting the ask to the reader's stake, not your deadline.","Frame the declaration as his voice, his account, on the record.","People engage with tasks that are theirs, not favors for the lawyer."],"focus":["impact","audience"],"placeholder":"This declaration is your chance to put your account of what happened on the official record, in your words — it's the single most important thing that tells your side of the story."},
    {"id":"narrative-law-early-10","level":"early","profession":"lawyer","title":"The opening line of the brief","scenario":"Your brief's first sentence is: 'This is an action for breach of contract arising under the parties' Master Services Agreement dated March 3.' Technically correct, utterly forgettable. The judge reads dozens of these. The first line should make her want to rule for you.","task":"Write a first sentence that frames the case around the wrong that was done, not the procedural label.","tips":["The first line sets the frame the judge reads the rest through — make it yours.","Lead with the injustice, not the docket category.","'Defendant took delivery of $400,000 in goods and refused to pay a cent' beats a caption."],"focus":["impact","clarity"],"placeholder":"Defendant accepted every dollar of goods our client delivered, then refused to pay for a single one."},
    {"id":"narrative-law-early-11","level":"early","profession":"lawyer","title":"Persuading the partner to change course","scenario":"You believe the team is pursuing the wrong theory — the fraud claim is a stretch, but the breach claim is airtight. To persuade the partner to drop fraud and focus, you can't just criticize; you need to show the better path and why it wins.","task":"Write a 3-4 sentence case for the change that leads with the upside of the new direction.","tips":["Persuasion to change course leads with the better destination, not the current flaw.","Show what focusing gains — a cleaner, faster, more winnable case.","Name the fraud claim's specific weakness as support, not as the headline."],"focus":["impact","structure"],"placeholder":"I think we win faster and cleaner if we drop the fraud claim and go all-in on breach — here's why the breach case is airtight and the fraud claim is a liability:"},
    {"id":"narrative-law-early-12","level":"early","profession":"lawyer","title":"The stakes for the small-business client","scenario":"Your small-business client is downplaying a trademark dispute as a nuisance. To persuade them to take it seriously, you need to make the stakes concrete in their world: if they lose the mark, they lose the brand their entire customer base recognizes, plus the cost of rebranding.","task":"Write a 2-3 sentence passage making the stakes real in the owner's own terms.","tips":["Translate the legal stake into the owner's business reality.","Losing a trademark isn't abstract — it's losing the name customers search for.","Concrete business consequences persuade a founder that 'legal risk' won't."],"focus":["impact","audience"],"placeholder":"If we lose this, you lose the name your customers know you by — every sign, every label, every search result, plus the cost of rebuilding recognition from scratch."},
    {"id":"narrative-law-early-13","level":"early","profession":"lawyer","title":"Pre-empting the client's 'too expensive'","scenario":"You're recommending a full document review before the deposition, which the cost-conscious client will resist as expensive. Persuade by pre-empting the objection: frame the review as insurance against the far larger cost of a surprise document blowing up the deposition.","task":"Write a 3-4 sentence recommendation that raises the cost concern and reframes it against the bigger risk.","tips":["Pre-empt the objection you know is coming — 'I know this sounds expensive, but.'","Reframe the cost against the larger cost it prevents.","Naming their concern first shows you're thinking about their money, not just yours."],"focus":["impact","audience"],"placeholder":"I know a full review sounds like a big spend, but here's the trade: a few thousand now versus the deposition being derailed by a document we didn't see coming —"},
    {"id":"narrative-law-early-14","level":"early","profession":"lawyer","title":"The witness prep that reframes the fear","scenario":"The client's employee is terrified of her deposition and it's affecting her preparation. Persuading her to engage means reframing the story she's telling herself — from 'I'm on trial' to 'I'm the person who knows the truth and gets to tell it.'","task":"Write a 3-4 sentence reframe that changes her narrative about the deposition.","tips":["Persuasion sometimes means changing the story the person tells themselves.","Shift the frame from threat to role: she's the truth-teller, not the accused.","A calmer narrative produces a better witness — the reframe is strategic, not just kind."],"focus":["impact","audience"],"placeholder":"Here's how I'd think about it: you're not on trial — you're the person who was actually there and knows what really happened. Your only job is to tell that truth simply."},
    {"id":"narrative-law-early-15","level":"early","profession":"lawyer","title":"The 'why this clause matters' to the client","scenario":"The client wants to strike an indemnity clause you fought to include because it 'complicates the deal.' To persuade them to keep it, tell the story of what it prevents: the one scenario where, without it, a supplier's mistake becomes the client's uncapped liability.","task":"Write a 3-4 sentence passage that shows, through a concrete scenario, why the clause earns its place.","tips":["An abstract clause is easy to cut; a scenario it prevents is not.","Walk them through the exact situation where the clause saves them.","Persuade with the story of the harm avoided, not the doctrine."],"focus":["impact","structure"],"placeholder":"I'd keep that clause, and here's the scenario it's built for: the supplier's defective part causes a customer injury, the customer sues you, and without the indemnity, you eat the entire cost —"},
    {"id":"narrative-law-early-16","level":"early","profession":"lawyer","title":"The mediation opening statement","scenario":"You have five minutes to open at mediation, with the other side's principal in the room. A recitation of your legal claims won't move them. A story — of a reasonable client wronged by a partner who broke the deal — might make their client want to resolve it.","task":"Write a 3-4 sentence opening that speaks past opposing counsel to their client's sense of fairness.","tips":["At mediation, the audience is the other side's decision-maker, not their lawyer.","Tell the story so their client recognizes the unfairness.","Persuasion in mediation is making the other side want to settle, not proving you'd win."],"focus":["impact","audience"],"placeholder":"We're here because a fair deal was broken. Our client held up every end of the bargain, and what happened next is something I think everyone in this room, on reflection, would call unfair —"},
    {"id":"narrative-law-early-17","level":"early","profession":"lawyer","title":"Framing the negotiation ask","scenario":"You're asking the counterparty to extend the payment terms for the client. Framed as 'we want more time,' it sounds like weakness. Framed as 'aligning payment with the delivery milestones we both agreed to,' it sounds like fairness. The framing changes whether they say yes.","task":"Write a 2-3 sentence ask that frames the request as mutually fair, not as a favor.","tips":["The same ask framed as fairness lands better than framed as need.","Anchor to something you both already agreed to — the delivery schedule.","Frame it as fixing a misalignment, not asking for a concession."],"focus":["impact","audience"],"placeholder":"We'd like to align the payment dates with the delivery milestones we already agreed to — right now they're mismatched, and syncing them is fairer to both sides:"},
    {"id":"narrative-law-early-18","level":"early","profession":"lawyer","title":"The client alert that drives action","scenario":"A new regulation affects the client, and the firm sends a client alert. Most alerts are dry summaries that get filed and forgotten. To drive the client to actually call you, the alert needs to frame the change as a specific, dated threat to their business, not a legal-update FYI.","task":"Write a 2-3 sentence alert opening that frames the change as something requiring their action, with the stakes.","tips":["An alert that reads as FYI gets filed; one that reads as a deadline gets a call.","Lead with what changes for them and when, not the statute's name.","Give the concrete consequence of doing nothing before the citation."],"focus":["impact","audience"],"placeholder":"Starting July 1, a new rule means your current data practices could trigger fines — and the fix takes weeks to implement, so the time to act is now, not July:"},
    {"id":"narrative-law-early-19","level":"early","profession":"lawyer","title":"The strongest-objection sandwich in the memo","scenario":"Your memo recommends a course of action, but there's a genuine risk you're tempted to bury in a footnote. Burying it makes the memo look naive when the partner spots it. Addressing it head-on — acknowledging, then answering — makes the recommendation bulletproof.","task":"Write a 3-4 sentence passage that surfaces the strongest objection to your recommendation and answers it.","tips":["Burying the best objection makes you look like you missed it.","Surface it, steelman it, then answer it — that's how you earn trust.","A recommendation that survives its own strongest objection is far more persuasive."],"focus":["impact","structure"],"placeholder":"The strongest argument against this recommendation is that the counterparty could claim we acted in bad faith. I've thought hard about that, and here's why it doesn't hold:"},
    {"id":"narrative-law-early-20","level":"early","profession":"lawyer","title":"The 'here's what changed' status that builds momentum","scenario":"You're updating the client after a good week, but your draft lists tasks flatly. To keep the client confident and engaged, frame the update as forward motion — where things stood, what shifted, and what it sets up next.","task":"Write a 3-4 sentence update that tells a story of momentum: before, the shift, what's now possible.","tips":["A status update can build confidence by telling a story, not listing tasks.","Frame the week as a turn: 'we were stuck on X, now that's resolved, which opens Y.'","Momentum is persuasive — it makes the client trust the trajectory."],"focus":["impact","structure"],"placeholder":"A week ago we were blocked on the other side's production; that broke loose Tuesday, and now that we have their financials, we can finally"},
    {"id":"narrative-law-early-21","level":"early","profession":"lawyer","title":"Persuading a reluctant witness to cooperate","scenario":"A former employee of the client — a friendly but nervous witness — is dodging your calls about giving a statement. He fears getting dragged into a fight that isn't his. Persuading him means addressing that fear and framing his role as small, safe, and meaningful.","task":"Write a 3-4 sentence message that acknowledges his concern and reframes his involvement as low-cost and worthwhile.","tips":["Address the fear directly before making the ask.","Frame his role accurately as bounded — one conversation, the truth, then done.","Persuasion here is removing the obstacle, not adding pressure."],"focus":["impact","audience"],"placeholder":"I understand you'd rather not get pulled into this — and I want to be clear that your role is small and simple: one conversation about what you saw, nothing more. Here's why it matters:"},
    {"id":"narrative-law-early-22","level":"early","profession":"lawyer","title":"The cover note that sells the redline","scenario":"You're sending a heavily marked-up contract back to the other side. If the cover note just says 'see attached,' the volume of redlines reads as hostility. Framing them as reasonable, cooperative, and aimed at getting the deal done changes how they're received.","task":"Write a 2-3 sentence cover note that frames the redlines as constructive, keeping the relationship productive.","tips":["Frame extensive redlines as collaboration toward closing, not attack.","Name the shared goal — getting to signature — up front.","A cooperative frame makes the other side more likely to accept your changes."],"focus":["impact","audience"],"placeholder":"Attached are our comments — all aimed at getting us to a signable deal quickly. Most are minor cleanups; the few substantive ones are flagged, and we're happy to talk through any of them:"},
    {"id":"narrative-law-early-23","level":"early","profession":"lawyer","title":"The stakes in the fee-justification memo","scenario":"You need to persuade the client to approve a larger litigation budget. A line-item breakdown alone reads as 'lawyers want more money.' The persuasion is in framing the spend against what's at stake — the exposure the budget is designed to protect.","task":"Write a 3-4 sentence justification that frames the budget as protecting a larger value, with the numbers.","tips":["Frame cost against the value it protects, not as a standalone number.","$150K in defense costs looks different next to $2M in exposure.","Persuade by making the ratio, not just the cost, visible."],"focus":["impact","precision"],"placeholder":"The proposed budget is $150K — set against exposure we estimate at $2M, this is spending 7 cents to protect a dollar. Here's what that budget buys and why each piece matters:"},
    {"id":"narrative-law-early-24","level":"early","profession":"lawyer","title":"The concession framed as a gift","scenario":"In the negotiation, you're prepared to concede a point that costs the client little but the other side values highly. Framing it as a reluctant give — rather than something you never cared about — lets you claim credit and ask for something in return.","task":"Write a 2-3 sentence passage that frames the concession as meaningful, positioning it for a trade.","tips":["A concession framed as easy gets nothing; framed as a real give, it earns a trade.","Signal the value you're placing on it before you give it.","Persuasion in negotiation is making your gives feel costly and your asks feel fair."],"focus":["impact","audience"],"placeholder":"We can agree to the exclusivity term — that's a real concession for us, and one we're only making because we want this deal to work. In return, we'd ask that you"},
    {"id":"narrative-law-early-25","level":"early","profession":"lawyer","title":"The closing argument for settling, to your own client","scenario":"After months of fighting, you're convinced the client should settle, but they're emotionally invested in vindication at trial. Persuading them means honoring what they've been through, framing settlement not as surrender but as the smart close to a story they can be proud of.","task":"Write a 4-sentence passage that persuades the client to settle by honoring their fight and reframing the ending.","tips":["Persuading an emotionally invested client requires honoring the emotion, not dismissing it.","Reframe settlement as winning on their terms, not giving up.","Tie the recommendation to their story: they fought, they made their point, now they secure the outcome."],"focus":["impact","audience"],"placeholder":"You fought hard and you made your point — the other side moved 40% because you refused to be pushed around. Settling now isn't backing down; it's taking the win you earned and walking away on your terms instead of gambling it on a jury —"}
  ],
  "delivering-hard-messages": [
    {"id":"hard-law-early-01","level":"early","profession":"lawyer","title":"The case is weaker than they hoped","scenario":"The client came in confident they had a slam-dunk. Your research shows the case is genuinely difficult — a key document cuts against them. You've been softening the news across three paragraphs of throat-clearing, which only makes the client more anxious about what's coming.","task":"Write a 3-4 sentence message that front-loads the hard news, then explains it.","tips":["Clear is kind — burying bad news in preamble is crueler than stating it.","Lead with the news: the case is harder than it looked, and here's the one reason.","After the honest headline, give the path — what this means and what you'd do."],"focus":["clarity","impact"],"placeholder":"I have to be straight with you: this case is harder than it first looked. A document in their production directly undercuts our main argument — here's what it says and where that leaves us:"},
    {"id":"hard-law-early-02","level":"early","profession":"lawyer","title":"Declining the partner's request, cleanly","scenario":"The partner asks you to take on the Kessler matter, but you're already at capacity on two deadline-driven cases, and taking a third means all three suffer. You need to say no — but your draft is a maze of maybe-ifs that reads like a reluctant yes.","task":"Write a 2-3 sentence response that gives a clean no with the reason and an alternative.","tips":["A clean 'no, because' respects everyone more than a hedged maybe.","State the real constraint: two deadlines that a third case would jeopardize.","Offer a path — later availability, or who could take it now."],"focus":["clarity","impact"],"placeholder":"I can't take Kessler right now without putting the two deadline cases at risk. If it can wait two weeks I'm all in; if not, Priya has bandwidth this week."},
    {"id":"hard-law-early-03","level":"early","profession":"lawyer","title":"Telling the client they missed the deadline","scenario":"The client sat on your advice and now the filing deadline has passed — the claim is likely lost, and it's largely because they didn't act when you told them to. You need to deliver this without either sugarcoating it or turning it into an accusation.","task":"Write a 3-4 sentence message that states the consequence honestly, assigns cause factually, and moves to what's left.","tips":["Front-load the consequence: the deadline passed and the claim is likely gone.","State the cause as fact, not blame — 'the decision wasn't made in time.'","Pivot to any remaining options so it isn't purely a message of loss."],"focus":["clarity","impact"]},
    {"id":"hard-law-early-04","level":"early","profession":"lawyer","title":"The behavior-impact-ask to a paralegal","scenario":"A paralegal on your team has twice sent documents to opposing counsel without the required privilege check. It's a serious risk. You need to address it directly but constructively — behavior, impact, and a specific ask, not a vague 'be more careful.'","task":"Write a 3-4 sentence message using behavior, impact, then ask.","tips":["Name the specific behavior, not a character judgment.","State the impact plainly — this could waive privilege and harm the client.","End with a concrete, doable ask, not 'be careful.'"],"focus":["clarity","impact"],"placeholder":"Twice this week, documents went to opposing counsel before the privilege review was done. That's a real risk — one wrong document out the door can waive privilege for the whole set. Going forward, I need every outbound production to clear the privilege check first, no exceptions —"},
    {"id":"hard-law-early-05","level":"early","profession":"lawyer","title":"Bad news to the client's CFO on the number","scenario":"The exposure you initially estimated at $200K has grown to $500K after discovery revealed additional claims. The CFO budgeted around the first number. You have to deliver the revised figure without hiding it behind a wall of explanation for why it changed.","task":"Write a 2-3 sentence message that leads with the new number, then the reason.","tips":["Lead with the number — the CFO needs it before the story of how it grew.","One clear sentence on why it changed, not a defensive paragraph.","Offer the next step: revised budget, or a call to work through options."],"focus":["clarity","impact"],"placeholder":"I need to revise our exposure estimate upward: it's now roughly $500K, not the $200K we discussed. The increase is from two additional claims discovery surfaced —"},
    {"id":"hard-law-early-06","level":"early","profession":"lawyer","title":"Saying no to the client's aggressive request","scenario":"The client wants you to send a threatening letter you consider baseless and potentially sanctionable. You have to refuse — but the client is paying and expects you to be their advocate. A wishy-washy no invites them to push; a preachy one damages the relationship.","task":"Write a 3-4 sentence response that declines firmly, explains the real risk to them, and offers the legitimate alternative.","tips":["A clean 'I won't do that, and here's the risk to you' beats a moralizing refusal.","Frame the no around their interest — a baseless letter can backfire on them.","Offer the strong, defensible version of what they actually want."],"focus":["clarity","impact"],"placeholder":"I can't send that letter — not to be difficult, but because it could expose you to sanctions and hand them the moral high ground. Here's the version that gets you what you want without the risk:"},
    {"id":"hard-law-early-07","level":"early","profession":"lawyer","title":"The 'we lost the motion' email","scenario":"The court denied your motion to dismiss. It's a setback but not fatal. Your draft opens with a long procedural explanation before the client learns the result, which will make the two minutes before they reach the news feel like an ambush.","task":"Write a 2-3 sentence email that states the loss first, its real significance, and the path forward.","tips":["State the result in the first sentence — don't make them wait through analysis.","Immediately calibrate the significance: setback, not disaster, and why.","End on the next move so the message isn't just bad news."],"focus":["clarity","impact"],"placeholder":"The court denied our motion to dismiss. It's a setback but not a serious one — it just means the case proceeds to discovery, which we were prepared for. Here's the plan from here:"},
    {"id":"hard-law-early-08","level":"early","profession":"lawyer","title":"Correcting the senior associate, respectfully","scenario":"A senior associate asked you to make an argument in the brief that you're confident is legally wrong and could draw a sanction. You're junior, but you're right. Staying silent is the easy path and the wrong one. You need to raise it clearly without insubordination.","task":"Write a 3-4 sentence message that respectfully flags the problem with the specific concern.","tips":["Raising a hard disagreement upward requires respect plus a concrete concern.","Lead with deference to their call, then the specific legal problem.","Frame it as protecting the team, not correcting the senior."],"focus":["clarity","impact"],"placeholder":"I want to flag something before I draft that argument — I'm worried it may cross a line that could draw a sanction. Here's the specific issue and a safer way to make the same point:"},
    {"id":"hard-law-early-09","level":"early","profession":"lawyer","title":"Telling the client their key witness has a problem","scenario":"The client's star witness — a former executive they trust — has a credibility problem you discovered: a prior inconsistent statement that opposing counsel will exploit. The client won't want to hear it, but they need to before building their case on him.","task":"Write a 3-4 sentence message that delivers the problem clearly and constructively.","tips":["Front-load the problem: the witness has a vulnerability we have to plan around.","Be specific about the risk — the prior statement and how it'll be used.","Move to strategy: how you'd handle it, not just that it exists."],"focus":["clarity","impact"]},
    {"id":"hard-law-early-10","level":"early","profession":"lawyer","title":"The uncomfortable fee conversation","scenario":"The client is disputing the bill and implying you over-worked the matter. You didn't — the hours were driven by their own late document production and repeated scope changes. You need to hold the line on the bill without an accusatory tone.","task":"Write a 3-4 sentence message that addresses the dispute factually and firmly, without blame-shifting.","tips":["Hold the line with facts, not defensiveness.","Attribute the hours to specific drivers without accusing the client.","Offer to walk through the entries — transparency defuses a fee fight."],"focus":["clarity","precision"],"placeholder":"I understand the bill is higher than you expected, and I want to be transparent about why. The bulk of the extra hours came from two things — the document production arriving in stages and the two scope changes in March. I'm happy to walk through the entries line by line —"},
    {"id":"hard-law-early-11","level":"early","profession":"lawyer","title":"Delivering a 'you have no case' to a hopeful intake","scenario":"A prospective client came to you certain they were wronged. After review, they have no viable legal claim — the conduct was unfair but not unlawful. You have to tell them clearly, because false hope wastes their time and money.","task":"Write a 3-4 sentence message that delivers the honest 'no case' with respect and, where possible, a useful redirect.","tips":["Clear is kind — a soft maybe here costs them money chasing nothing.","Separate the human validation (this was unfair) from the legal reality (not actionable).","Offer any legitimate alternative — a different forum, a non-legal path."],"focus":["clarity","impact"],"placeholder":"I've looked carefully, and I have to be honest with you: what happened to you was unfair, but it isn't something the law gives you a claim for. I don't want you spending money chasing a case that won't succeed. What might actually help is"},
    {"id":"hard-law-early-12","level":"early","profession":"lawyer","title":"Owning your own missed deadline to the partner","scenario":"You miscalendared a discovery response and it's now two days late. It's fixable but the partner must know immediately. The temptation is to bury it in a longer update or explain the calendaring mixup first. Front-load it.","task":"Write a 2-3 sentence message that owns the miss first, then the fix and the impact.","tips":["Lead with the miss — the partner should not have to find it.","State the fix and whether there's real prejudice, honestly.","Own it without the paragraph of self-defense; the fix matters more."],"focus":["clarity","impact"],"placeholder":"I need to flag a mistake: I miscalendared the discovery response and it's two days overdue. I've already contacted opposing counsel, who agreed to accept it tomorrow with no motion — so no lasting harm, but you should know."},
    {"id":"hard-law-early-13","level":"early","profession":"lawyer","title":"The feedback to the junior on their memo","scenario":"A first-year's memo you're reviewing has a serious analytical gap — they missed a controlling case. You want to help them grow, not crush them. Vague praise helps nobody; harsh criticism helps nobody. Behavior, impact, ask.","task":"Write a 3-4 sentence feedback message that names the gap specifically and constructively.","tips":["Name the specific gap — the missed case — not 'the analysis was weak.'","State the impact: a memo that misses controlling law can mislead the partner.","End with a concrete ask and an offer to help, not just criticism."],"focus":["clarity","impact"],"placeholder":"Your structure and writing are strong — one substantive gap to fix: the memo misses the controlling case, Ellis v. Warner, which changes the analysis on the second issue. Because a partner will rely on this, that gap matters. Let's add it —"},
    {"id":"hard-law-early-14","level":"early","profession":"lawyer","title":"The client can't do what they want to do","scenario":"The client wants to publicly announce the settlement, but the agreement contains a strict confidentiality clause with a penalty. You have to tell them no, clearly, because a breach here has real financial teeth.","task":"Write a 2-3 sentence message that delivers the hard no, the reason, and the consequence of ignoring it.","tips":["State the no plainly — they cannot announce it.","Give the specific reason: the confidentiality clause and its penalty.","Make the consequence concrete so the no is understood, not resented."],"focus":["clarity","impact"],"placeholder":"I have to be direct: you can't announce the settlement. The agreement's confidentiality clause is strict, and breaching it carries a penalty that could erase much of what you recovered —"},
    {"id":"hard-law-early-15","level":"early","profession":"lawyer","title":"Telling opposing counsel their client blew a deadline","scenario":"The other side missed a discovery deadline, and you need to notify them formally before moving to compel. The message should be firm and professional — not gloating, not aggressive, but clear that the clock has run and you'll act.","task":"Write a 2-3 sentence message that states the missed deadline and your next step, professionally.","tips":["State the fact — the deadline passed — without editorializing.","Name your next step clearly so it's a warning, not a surprise.","Firm and professional beats aggressive; you may face this lawyer for years."],"focus":["clarity","precision"],"placeholder":"The deadline for your client's document production was Tuesday, and we haven't received anything. Unless the production arrives by Friday, we'll move to compel —"},
    {"id":"hard-law-early-16","level":"early","profession":"lawyer","title":"The 'this will cost more than it's worth' advice","scenario":"The client wants to pursue a $15,000 claim that will cost $40,000 to litigate. They're driven by principle. You have to tell them the economics don't work, even knowing they want to fight, because letting them spend into a loss would be a disservice.","task":"Write a 3-4 sentence message that delivers the uncomfortable economic reality and respects the principle behind their wish.","tips":["Acknowledge the principle before delivering the math — dismissing it loses them.","State the numbers plainly: the fight costs more than the win.","Offer a proportionate path — a demand letter, small claims — so it's not just no."],"focus":["clarity","impact"],"placeholder":"I understand this is about principle, not just money — and I respect that. But I have to be straight with the economics: pursuing this in court would cost around $40,000 to recover $15,000. Here's a proportionate way to make your point without spending into a loss:"},
    {"id":"hard-law-early-17","level":"early","profession":"lawyer","title":"Raising a colleague's error that affects your work","scenario":"Another associate's draft that you're building on contains an error that, uncorrected, will undermine the filing. You need to raise it with them directly — not go around them to the partner, not let it slide. Behavior, impact, ask, peer to peer.","task":"Write a 2-3 sentence message that flags the error collegially with the specific impact.","tips":["Peer-to-peer, lead with the specific issue, not a judgment.","State why it matters — the filing depends on it being right.","Frame as fixing it together, keeping the relationship intact."],"focus":["clarity","impact"],"placeholder":"Building on your draft I hit something worth flagging — the damages figure in Section 3 doesn't match the exhibit, and since the filing relies on it, I wanted to catch it with you before it goes out:"},
    {"id":"hard-law-early-18","level":"early","profession":"lawyer","title":"The settlement is worse than they wanted","scenario":"After negotiation, the best achievable settlement is $250K — well below the client's $400K expectation, but a fair outcome given the case's real weaknesses. You have to deliver the number and recommend acceptance, knowing it will disappoint.","task":"Write a 3-4 sentence message that delivers the number, the honest reason it's fair, and your recommendation.","tips":["Lead with the number — don't stretch out the disappointment.","Explain why it's fair given the real case, not just assert it.","Give your recommendation clearly; the client wants your judgment, not just the news."],"focus":["clarity","impact"]},
    {"id":"hard-law-early-19","level":"early","profession":"lawyer","title":"Telling the client about your firm's conflict","scenario":"Your firm has discovered a conflict of interest that means you may have to withdraw from part of the matter. This is awkward and the client will be frustrated. You have to disclose it clearly and promptly, because delay makes it worse and it's an ethical obligation.","task":"Write a 3-4 sentence message that discloses the conflict honestly and outlines the practical next steps.","tips":["Disclose promptly and plainly — a delayed or muffled conflict disclosure erodes trust fast.","State what it means concretely for their representation.","Move immediately to the plan: what continues, what needs new counsel, timing."],"focus":["clarity","impact"],"placeholder":"I need to raise something important and time-sensitive: we've identified a conflict that affects part of your matter. Here's exactly what it means for you and what we'll do about it —"},
    {"id":"hard-law-early-20","level":"early","profession":"lawyer","title":"The 'I can't promise that timeline' pushback","scenario":"The client demands the closing happen by month-end, but three third-party consents are outside your control and unlikely to arrive that fast. Promising the date would be a lie you'll have to walk back. You have to reset the expectation now.","task":"Write a 2-3 sentence message that declines to promise the date, explains the real constraint, and gives an honest estimate.","tips":["Don't promise what you can't control — a walked-back promise is worse than an honest 'no.'","Name the specific constraint: consents you don't control.","Give the honest date and what would have to happen to beat it."],"focus":["clarity","precision"],"placeholder":"I can't honestly promise a month-end close — it hinges on three consents from parties we don't control. Realistically I'd target mid-next-month, and here's what would have to break our way to move it up:"},
    {"id":"hard-law-early-21","level":"early","profession":"lawyer","title":"Declining to backdate a document","scenario":"The client asks you to date a signed agreement to last month 'so it lines up with the invoices.' That's backdating, and you won't do it. You need to refuse firmly and explain why without lecturing, while offering the legitimate way to achieve their actual goal.","task":"Write a 2-3 sentence response that refuses clearly and redirects to the lawful path.","tips":["Refuse plainly — no wiggle room that invites a second ask.","Name the risk to them, not just the rule — backdating can be fraud.","Offer the legitimate mechanism that solves their real problem."],"focus":["clarity","impact"],"placeholder":"I can't date it to last month — that's backdating, and it could expose you to a fraud claim that's far worse than the invoice mismatch. What we can do instead is add an effective-date clause that legitimately ties it to"},
    {"id":"hard-law-early-22","level":"early","profession":"lawyer","title":"The bad discovery finding the client must hear","scenario":"In reviewing the client's own documents, you found a smoking-gun email that badly damages their position — their own executive admitted the problem in writing. The client won't want to hear it, but they must, because it changes the whole strategy.","task":"Write a 3-4 sentence message that delivers the damaging finding clearly and turns to what to do about it.","tips":["Front-load the finding — soft-pedaling a smoking gun helps no one.","Be specific: the document, who wrote it, what it says.","Immediately move to strategy — this changes the plan, here's how."],"focus":["clarity","impact"],"placeholder":"I found something in your own files you need to know about right away: an email from your operations head admitting the defect was known before shipment. This is damaging, and it changes our strategy — here's how I'd handle it:"},
    {"id":"hard-law-early-23","level":"early","profession":"lawyer","title":"Setting a boundary with a 24/7 client","scenario":"A client has started calling and texting at all hours expecting instant responses, and it's unsustainable. You need to set a boundary that protects your ability to do good work without damaging the relationship or seeming unavailable for genuine emergencies.","task":"Write a 3-4 sentence message that sets the boundary respectfully while preserving responsiveness for true urgencies.","tips":["Set the boundary as a way to serve them better, not to be less available.","Be specific about response times and the channel for real emergencies.","A clear boundary respectfully stated protects the relationship, not threatens it."],"focus":["clarity","audience"],"placeholder":"I want to make sure I'm giving your matter my best work, and that means setting some structure on communication: I'll respond to emails within a business day, and for anything genuinely urgent, call my cell and I'll pick up. Here's how I'd suggest we handle the different levels of urgency:"},
    {"id":"hard-law-early-24","level":"early","profession":"lawyer","title":"The 'we may have to withdraw the argument' to the partner","scenario":"After more research, you've concluded that an argument already in the filed brief is weaker than the team thought and might backfire. You have to tell the partner it may need to be withdrawn or amended — an uncomfortable message about work already done.","task":"Write a 3-4 sentence message that raises the problem honestly and proposes a concrete fix.","tips":["Deliver the uncomfortable conclusion directly — don't cushion it into invisibility.","Be specific about why the argument is now a liability.","Propose the fix: withdraw, amend, or supplement — with your recommendation."],"focus":["clarity","impact"],"placeholder":"I have an uncomfortable finding on the brief we already filed: the third argument is weaker than we assessed and could actually hurt us if the judge probes it. Here's the specific problem and how I'd suggest we fix it:"},
    {"id":"hard-law-early-25","level":"early","profession":"lawyer","title":"Telling the client the outcome, and it's a loss","scenario":"The court ruled against your client after trial. It's the worst news of the matter. You have to call and deliver it — clearly, without hiding behind procedure, honoring their effort, and turning to what comes next (appeal options, practical steps).","task":"Write a 4-sentence message that delivers the loss directly, acknowledges the effort, and moves to next steps.","tips":["Say the result first and plainly — a loss delivered slowly is a loss delivered twice.","Acknowledge what they put into it before pivoting.","Give the concrete next steps — appeal, timing — so they aren't left in freefall."],"focus":["clarity","impact"],"placeholder":"I have hard news: the court ruled against us. I know how much you put into this, and I'm sorry it went this way. It isn't necessarily the end — we have appeal options, and here's the decision we need to make in the next few weeks:"}
  ],
  "putting-it-together": [
    {"id":"together-law-early-01","level":"early","profession":"lawyer","title":"The full client update, done right","scenario":"Your monthly update to the client's GC needs to cover a decision she owes you, a good result, a risk, and the budget. It has to lead with the point, be structured, precise, and cut to what matters — all in an email she'll read on her phone between meetings.","task":"Write the complete update (5-7 sentences) integrating BLUF, structure, and precision.","tips":["Lead with the decision she owes you — that's the action item.","Signpost the sections so she can navigate on a phone.","Every claim gets a number or a date; cut anything that would appear in every update."],"focus":["structure","precision"],"placeholder":"One decision needed this week, plus three quick updates. DECISION: approve the revised $300K settlement authority before Friday's mediation. RESULT:"},
    {"id":"together-law-early-02","level":"early","profession":"lawyer","title":"Match the register: text vs. memo","scenario":"You have the same substance — the deposition moved to April 10 and the client needs to reschedule two witnesses — to deliver in two channels: a quick text to the busy partner, and a formal note to the client's HR coordinator. The register must differ.","task":"Write both versions: the 1-sentence partner text and the 3-4 sentence formal client note.","tips":["Channel dictates register — the text is shorthand, the note is complete and courteous.","The partner needs only the delta; the coordinator needs the full instruction.","Same facts, two registers — matching each to its reader is the skill."],"focus":["audience","concision"],"placeholder":"Partner text: Depo moved to 4/10 — need to reslot the two witnesses. Client note: I'm writing to let you know the deposition has been rescheduled to April 10 —"},
    {"id":"together-law-early-03","level":"early","profession":"lawyer","title":"Edit like a reader: the memo pass","scenario":"You've drafted a research memo and it's technically complete but bloated — hedges, meta-commentary, a buried conclusion. Before it goes to the partner, you need to edit it as she'll read it: what does she see first, what does she need, what can go.","task":"Write the revised opening paragraph (3-4 sentences) after editing for BLUF, concision, and precision.","tips":["Read your own draft as the partner will — where does her eye go, what does she skip.","Move the conclusion to the top; cut the roadmap and the hedges.","Every sentence earns its place or gets cut — edit like the reader's time is yours to protect."],"focus":["concision","structure"],"placeholder":"The client can enforce the non-solicitation clause, with one fixable weakness in the geographic scope. This conclusion rests on three points:"},
    {"id":"together-law-early-04","level":"early","profession":"lawyer","title":"The high-stakes email under real constraints","scenario":"Opposing counsel just made a settlement offer that expires in 24 hours; the partner is on a flight; and the client's decision-maker only reads short emails. You have to convey the offer, your recommendation, and the deadline — persuasively, precisely, in a form each reader can act on fast.","task":"Write the email (4-6 sentences) integrating BLUF, recommendation, and urgency for a time-pressured reader.","tips":["Lead with the offer and the deadline — the constraints demand it.","Own a recommendation; a menu wastes the 24 hours.","Make the stakes and the math concrete so a fast decision is an informed one."],"focus":["impact","structure"],"placeholder":"Time-sensitive: they offered $280K, expiring tomorrow at 5pm, and I recommend we accept. Here's why in two lines:"},
    {"id":"together-law-early-05","level":"early","profession":"lawyer","title":"The plain-language contract summary for the board","scenario":"The client's board needs to understand the key terms of a major contract before approving it. You must translate legal terms into plain business language, structure it around what matters to them, and keep it to a page they'll actually read.","task":"Write the summary (5-7 sentences) integrating audience translation, structure, and concision.","tips":["Translate every legal term into a business consequence the board cares about.","Structure around their decisions — obligations, risks, exits — not contract order.","One page, plain language, no legalese survives the board's patience."],"focus":["audience","structure"],"placeholder":"This contract commits us to three things and protects us on two. What you're approving, in plain terms:"},
    {"id":"together-law-early-06","level":"early","profession":"lawyer","title":"The status call talking points","scenario":"You have fifteen minutes on a client call to cover four topics: a decision needed, a result, a risk, and a budget question. You need talking points that lead with the point, stay structured, and fit the time — spoken, not written.","task":"Write the 4 talking points as you'd say them aloud, each a lead-with-the-point headline.","tips":["Each point is a spoken headline, not a paragraph you'll read.","Order by what needs the client's action first.","Fifteen minutes is four points — resist the fifth."],"focus":["structure","concision"],"placeholder":"One: I need your call on the settlement authority today. Two: we won the motion to compel —"},
    {"id":"together-law-early-07","level":"early","profession":"lawyer","title":"The demand letter that persuades and holds up","scenario":"You're drafting a demand letter that has to do three jobs at once: tell a persuasive story of the wrong, state the legal claims precisely enough to be credible, and make a clear ask with a deadline. Too soft and it's ignored; too aggressive and it invites a fight.","task":"Write the letter's core (5-7 sentences) integrating narrative, precision, and a clear ask.","tips":["Open with the story of the wrong, then the precise legal basis.","State the specific ask and deadline — vagueness reads as bluffing.","Balance firmness with professionalism; this may become an exhibit."],"focus":["impact","precision"],"placeholder":"Our client delivered exactly what your client ordered, on time and to spec; your client accepted it and has refused to pay the $85,000 due. This is a straightforward breach of Sections 3 and 4 —"},
    {"id":"together-law-early-08","level":"early","profession":"lawyer","title":"The escalation email to the partner","scenario":"A matter has hit a real problem — the client withheld a key document, opposing counsel is threatening sanctions, and you need the partner's guidance today. You must convey the situation, the stakes, and your recommended action clearly, to a partner who's slammed.","task":"Write the escalation (4-6 sentences) integrating BLUF, structure, and a clear recommended action.","tips":["Lead with the problem and what you need from her — she's busy.","Structure the situation so she grasps it in one read.","End with your recommended action, not an open question — give her something to approve."],"focus":["structure","impact"],"placeholder":"I need 10 minutes today on a problem in Harding: the client withheld a document that opposing counsel now knows about, and they're threatening sanctions. Here's the situation and what I recommend:"},
    {"id":"together-law-early-09","level":"early","profession":"lawyer","title":"The witness prep memo, calibrated","scenario":"You're writing a prep memo for a nervous first-time witness. It has to explain the process plainly, structure the guidance so she can absorb it, cut the legalese, and reassure without misleading — everything at once, for an anxious non-lawyer.","task":"Write the memo's core guidance (5-7 sentences) integrating audience calibration, structure, and clarity.","tips":["Translate every procedural term into plain instruction.","Structure around her experience — before, during, after the deposition.","Reassure with truth: telling the truth simply is the whole strategy."],"focus":["audience","clarity"],"placeholder":"Your deposition is an interview under oath — no judge, no jury, just questions and your honest answers. Here's what to expect and the three rules that will carry you through:"},
    {"id":"together-law-early-10","level":"early","profession":"lawyer","title":"The negotiation recap that drives next steps","scenario":"After a three-hour negotiation, you need to send the client and partner a recap that captures what was agreed, what's still open, and what each side owes next — precise, structured, and short enough to be read, not filed.","task":"Write the recap (4-6 sentences) integrating structure, precision, and concision.","tips":["Three buckets: agreed, open, next actions with owners and dates.","Precise on the terms agreed — a fuzzy recap causes disputes later.","Short enough to read on arrival; detail available on request."],"focus":["structure","precision"],"placeholder":"Recap of today's session. AGREED: 4% royalty, 3-year term, mutual indemnity. OPEN: exclusivity scope. NEXT: they send revised language by Thursday; we respond by Monday —"},
    {"id":"together-law-early-11","level":"early","profession":"lawyer","title":"The hard-news update that keeps the client's trust","scenario":"You have to tell the client the case got harder (a bad document surfaced), recommend a strategy pivot, and keep them confident — all in one message. It requires hard-message delivery, a clear recommendation, and precision, without spin.","task":"Write the message (5-7 sentences) integrating clear bad news, recommendation, and honest framing.","tips":["Front-load the hard news, then the recommendation — clarity is the trust-builder.","Own a specific pivot, not a menu of worries.","Precision on what changed keeps it honest, not alarmist."],"focus":["impact","clarity"],"placeholder":"I have to be straight: a document surfaced that weakens our main argument, and I'm recommending we shift strategy. Here's exactly what it says, what it changes, and the stronger path I'd take instead:"},
    {"id":"together-law-early-12","level":"early","profession":"lawyer","title":"The one-pager for the busy in-house team","scenario":"The client's small legal team asked for a one-page summary of a complex regulatory change and what they must do. You must distill the law into actions, structure it for scanning, and cut everything that isn't a to-do or a deadline.","task":"Write the one-pager's core (5-7 sentences) integrating audience, structure, and concision.","tips":["Lead with the deadline and the one-line gist of the change.","Convert obligations into a checklist of dated actions.","Cut the statutory background; they want the to-do list, not the treatise."],"focus":["audience","structure"],"placeholder":"By September 30, three things must change in how you handle customer data. Here's the checklist, each with an owner and a deadline:"},
    {"id":"together-law-early-13","level":"early","profession":"lawyer","title":"The persuasive brief section, tightened","scenario":"You've drafted the argument section of a brief. It's persuasive but bloated — too many cases, a buried thesis, and it doesn't pre-empt the obvious counterargument. Edit it into a section that leads with the point, cites tightly, and answers the objection.","task":"Write the revised opening of the argument (4-6 sentences) integrating BLUF, precision, and objection-handling.","tips":["Lead with your governing point, then the best authority — not five cases.","Cite tightly; a wall of citations dilutes the strong one.","Pre-empt the strongest counterargument before opposing counsel raises it."],"focus":["impact","precision"],"placeholder":"The notice provision was not satisfied, and the single controlling case in this circuit settles it. Defendant will argue substantial compliance, but that argument fails because"},
    {"id":"together-law-early-14","level":"early","profession":"lawyer","title":"The 'here's where we are' for a new partner on the matter","scenario":"A new partner is taking over the matter and needs to get up to speed fast. You must brief her with the bottom line, the structure of what's in dispute, the precise status, and the decisions pending — a complete orientation she can absorb in one read.","task":"Write the orientation brief (6-8 sentences) integrating BLUF, structure, and precision.","tips":["Lead with the bottom line: where the matter stands and what's next.","Structure by the issues in dispute, not by chronology.","Precise on status — dates, numbers, pending decisions — so she can act immediately."],"focus":["structure","precision"],"placeholder":"Bottom line: we're mid-discovery, ahead on the merits, with one decision pending on settlement authority. The case turns on three issues:"},
    {"id":"together-law-early-15","level":"early","profession":"lawyer","title":"The client email that has to say no","scenario":"The client asked you to do something legally unwise, and you have to decline, explain the risk, offer an alternative, and preserve the relationship — a hard message delivered with presence and audience-awareness, all in one email.","task":"Write the email (4-6 sentences) integrating a clean no, the reason, and a constructive alternative.","tips":["Deliver the no cleanly, framed around their interest.","Give the specific risk, not a vague 'it's not advisable.'","Offer the legitimate path so the email ends with a yes to something."],"focus":["impact","audience"],"placeholder":"I can't do it the way you've asked, and I want to explain why plainly — it would expose you to a real risk, not just a technicality. Here's the risk, and here's the way to get what you actually want safely:"},
    {"id":"together-law-early-16","level":"early","profession":"lawyer","title":"The spoken answer in the partner meeting","scenario":"In the strategy meeting, the partner asks for your recommendation on whether to depose the CFO. You need to answer aloud with a clear position, a structured rationale, and enough precision to be credible — in 30 seconds, under everyone's eyes.","task":"Write the 30-second spoken answer integrating a clear recommendation (PREP) and precision.","tips":["Point first: yes, depose the CFO — then the reason.","One example or fact that proves the point, not three.","Land back on the point with the action; keep it to 30 seconds."],"focus":["impact","structure"],"placeholder":"Yes, we should depose the CFO. He signed the approval email that's central to the case, and only he can explain the gap in the timeline —"},
    {"id":"together-law-early-17","level":"early","profession":"lawyer","title":"The risk memo that earns action","scenario":"You've identified a serious risk in the client's proposed deal. Your memo has to make the risk concrete and vivid, quantify it, structure the options, and end with a clear recommendation — persuasion, precision, and presence together.","task":"Write the memo's core (5-7 sentences) integrating vivid stakes, quantified risk, and a recommendation.","tips":["Make the top risk vivid with a concrete scenario, then quantify it.","Structure the response options, then commit to one.","End with the recommendation and the number that justifies it."],"focus":["impact","precision"],"placeholder":"The deal carries one risk large enough to reconsider the whole structure: if the key customer walks, you lose 40% of the revenue you're paying for. Here's how that plays out, what it costs, and what I recommend:"},
    {"id":"together-law-early-18","level":"early","profession":"lawyer","title":"The multi-audience thread reply","scenario":"On a thread with both the client's CEO and the partner, you must answer the CEO's business question (can we close this quarter?) while giving the partner the legal precision she needs, in one reply, without contradiction or confusion.","task":"Write the reply (4-6 sentences) integrating a primary audience, precise detail, and clear structure.","tips":["Pick the CEO as primary; answer his question first, plainly.","Carry the partner's precision in a sentence the CEO can skim past.","One coherent message for both — never two contradictory ones."],"focus":["audience","structure"],"placeholder":"To your question, [CEO]: yes, closing this quarter is realistic, with one open item. The remaining legal detail, for the file: the disclosure schedules need the two consents finalized —"},
    {"id":"together-law-early-19","level":"early","profession":"lawyer","title":"The concise but complete client alert","scenario":"A court decision affects the client's industry, and you're writing the alert. It must grab attention with the stakes, translate the ruling into plain terms, be precise about what changed, and drive the client to call — persuasion, audience, and concision in one short piece.","task":"Write the alert (4-6 sentences) integrating a compelling frame, plain translation, and a clear call to action.","tips":["Lead with what the ruling changes for them, not the case name.","Translate the holding into a business consequence.","End with the specific action and why waiting costs them."],"focus":["audience","impact"],"placeholder":"A court ruling last week means the indemnity clauses in your standard contracts may no longer protect you the way you assumed. Here's what changed, in plain terms, and why it's worth a call this week:"},
    {"id":"together-law-early-20","level":"early","profession":"lawyer","title":"The settlement recommendation memo","scenario":"You're recommending the client accept a settlement. The memo must own the recommendation, structure the reasoning (expected value, cost, risk), be precise with the numbers, and pre-empt the client's desire to fight on — everything at once, for a disappointed reader.","task":"Write the memo's core (6-8 sentences) integrating recommendation, precise math, and objection-handling.","tips":["Own the recommendation up front — accept.","Show the expected-value math precisely; that's the persuasion.","Pre-empt 'but we could win' by pricing the risk and cost honestly."],"focus":["impact","precision"],"placeholder":"I recommend accepting the $250K offer. The math: expected trial value is about $300K, but reaching it costs roughly $80K and carries a 35% chance of losing entirely — so the offer is the better bet. I know the instinct is to push on, and here's why I'd resist it:"},
    {"id":"together-law-early-21","level":"early","profession":"lawyer","title":"The correction email you'd rather not send","scenario":"You made an error in advice you gave the client last week — you told them a deadline was in June when it's actually in May. You must correct it clearly, own it, convey the new urgency precisely, and keep their trust — hard message, precision, and presence together.","task":"Write the correction (4-6 sentences) integrating clean ownership, the corrected fact, and the new action needed.","tips":["Front-load the correction — don't bury it in a longer update.","Own the error plainly, then pivot fast to the corrected action.","Be precise about the new deadline and what it changes right now."],"focus":["clarity","impact"],"placeholder":"I need to correct something I told you last week, and it's time-sensitive: the filing deadline is May 15, not June 15 as I said. That's my error, and here's what it means we need to do this week:"},
    {"id":"together-law-early-22","level":"early","profession":"lawyer","title":"The deposition summary that's actually used","scenario":"You attended a full-day deposition and must produce a summary the partner will use to plan the next steps. It has to lead with the key admissions, be organized by theme, precise on what was said, and short enough to be read tonight — everything at once.","task":"Write the summary's structure and lead section (5-7 sentences) integrating BLUF, thematic structure, and precision.","tips":["Lead with the single most useful admission — the reason the summary exists.","Organize by theme (admissions, damage, credibility), not chronology.","Precise quotes or paraphrases with page cites; a fuzzy summary is unusable."],"focus":["structure","precision"],"placeholder":"Headline: the witness admitted no one reviewed the specs before approval (p. 84) — the admission we needed. The rest, by theme: KEY ADMISSIONS —"},
    {"id":"together-law-early-23","level":"early","profession":"lawyer","title":"The 'catch me up in one message' for the traveling partner","scenario":"The partner is at trial in another matter and texts: 'What's the state of play in Delgado? One message.' You must give her the whole picture — status, the one issue that needs her, and the deadline — in a single, structured, scannable message she reads between witnesses.","task":"Write the single catch-up message (4-6 sentences) integrating BLUF, structure, and concision.","tips":["Lead with the one thing that needs her, then the rest.","Structure it so she can scan it in ten seconds between witnesses.","Every line earns its place; this is one message, not a report."],"focus":["concision","structure"],"placeholder":"Delgado in one message: NEEDS YOU — approve the expert budget by tomorrow. STATUS — discovery closes Friday, on track. RISK —"},
    {"id":"together-law-early-24","level":"early","profession":"lawyer","title":"The client-facing summary of a complex deal risk","scenario":"The client is about to sign, and you've found a subtle but serious risk in the deal. You must explain it in plain language, make the stakes concrete, be precise about the exposure, and recommend a specific fix — all before they sign tomorrow, in an email they'll read tonight.","task":"Write the email (5-7 sentences) integrating plain translation, concrete stakes, precision, and a recommended fix.","tips":["Lead with the risk in plain terms and why it matters before signing.","Make the exposure concrete and quantified.","Recommend the specific fix, not just 'we should discuss.'"],"focus":["audience","precision"],"placeholder":"Before you sign tomorrow, one thing needs your attention: as drafted, the indemnity is uncapped, which means a single supplier failure could cost you far more than the deal is worth. Here's the exposure in numbers and the one-line fix I recommend:"},
    {"id":"together-law-early-25","level":"early","profession":"lawyer","title":"The capstone: the whole matter in one page","scenario":"The client's GC asked for a one-page 'where do we stand and what's the plan' on a matter you've run for six months. This is everything at once: lead with the bottom line, structure by issue, be precise on status and numbers, own the recommendations, and cut it to a page she'll read start to finish.","task":"Write the one-page brief (7-9 sentences) integrating BLUF, structure, precision, presence, and concision.","tips":["Open with the bottom line: where it stands, what's next, what you recommend.","Structure by the issues that matter, each with precise status.","Own the recommendations; end with the decisions she needs to make and by when."],"focus":["structure","precision"],"placeholder":"Bottom line: we're in a strong position heading into mediation next month, with one decision I need from you this week. Where things stand, by issue:"}
  ],
};
